values
  ('28', '새우 두부 계란찜', '반찬', '
연두부 75g(3/4모), 칵테일새우 20g(5마리), 달걀 30g(1/2개), 생크림 13g(1큰술), 설탕 5g(1작은술), 무염버터 5g(1작은술)
고명
시금치 10g(3줄기)', '["연두부","칵테일새우","달걀","생크림","설탕","무염버터","고명","시금치"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','6f10b4ad-53a2-4a07-ba89-19a6b074373d','c7d438a6-34d6-423f-905d-446b839e2f39','af187077-b7f6-4b0e-9e99-f844f6359ac2','06e6f3e7-0293-469d-a338-11a610f3e71b','7aabd532-361f-4240-aa33-6bfa1be4bc4e','9a7f4da6-531b-4478-89ff-d73beafcad1b']::uuid[], '[{"step":1,"text":"손질된 새우를 끓는 물에 데쳐 건진다.a","imageUrl":null},{"step":2,"text":"연두부, 달걀, 생크림, 설탕에 녹인 무염버터를 믹서에 넣고 간 뒤 새우(1)를 함께 섞어 그릇에 담는다.b","imageUrl":null},{"step":3,"text":"시금치를 잘게 다져 혼합물 그릇(2)에 뿌리고 찜기에 넣고 중간 불에서 10분 정도 찐다.c","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00028_2.png', 220, 3, 14, 17, 99),
  ('29', '부추 콩가루 찜', '반찬', '조선부추 50g, 날콩가루 7g(1⅓작은술)
, 저염간장 3g(2/3작은술), 다진 대파 5g(1작은술), 다진 마늘 2g(1/2쪽), 고춧가루 2g(1/3작은술), 요리당 2g(1/3작은술), 참기름 2g(1/3작은술), 참깨 약간', '["조선부추","날콩가루","저염간장","다진 대파","다진 마늘","고춧가루","요리당","참기름","참깨"]'::jsonb, ARRAY['058648c3-fd8e-476d-952f-b15dc67f1877','c1a987ee-fe94-4eb5-b3e7-d41c23cd3445','f175019d-5a93-4cd4-aabc-e7e79445f15a','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','84104c49-0af4-4323-a56b-b67002a422d9','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','0c0ade94-cfd8-4104-b44c-40e942cac482','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"부추는 깨끗이 씻어 물기를 제거하고, 5cm 길이로 썰고 부추에 날콩가루를 넣고 고루 섞이도록 버무린다.","imageUrl":null},{"step":2,"text":"찜기에 면보를 깔고 부추를 넣은 후 김이 오르게 쪄서 파랗게 익힌다.","imageUrl":null},{"step":3,"text":"저염간장에 다진 대파, 다진 마늘, 고춧가루, 요리당 , 참기름, 참깨를 섞어 양념장을 만들고 찐 부추는 그릇에 담아낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00029_2.png', 215, 20, 14, 9, 240),
  ('31', '방울토마토 소박이', '반찬', ' 
방울토마토 150g(5개), 양파 10g(3×1cm), 부추 10g(5줄기)
, 
고춧가루 4g(1작은술), 멸치액젓 3g(2/3작은술), 다진 마늘 2.5g(1/2쪽), 매실액 2g(1/3작은술), 설탕 2g(1/3작은술), 물 2ml(1/3작은술), 통깨 약간', '["방울토마토","양파","부추","고춧가루","멸치액젓","다진 마늘","매실액","설탕","물","통깨"]'::jsonb, ARRAY['aa597bcd-596b-4cbe-a2c4-3da0d060cb50','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','058648c3-fd8e-476d-952f-b15dc67f1877','84104c49-0af4-4323-a56b-b67002a422d9','5fd46a51-6998-4ac9-a1fb-cab1eedf7cd9','fc6e31ce-388e-45cd-956b-b238b9134eb1','02fd7135-0ec3-49ec-82e3-390536ab2cf5','06e6f3e7-0293-469d-a338-11a610f3e71b','94786475-832c-4f97-aab7-bf6fbbe2236b','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"물기를 빼고 2cm 정도의 크기로 썰은 부추와 양파를 양념장에 섞어 양념속을 만든다.","imageUrl":null},{"step":2,"text":"깨끗이 씻은 방울토마토는 꼭지를 떼고 윗부분에 칼로 십자모양으로 칼집을 낸다.","imageUrl":null},{"step":3,"text":"칼집을 낸 방울토마토에 양념속을 사이사이에 넣어 버무린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00031_2.png', 45, 9, 2, 1, 277),
  ('32', '순두부 사과 소스 오이무침', '반찬', '
오이 70g(1/3개), 다진 땅콩 10g(1큰술)
, 
순두부 40g(1/8봉지), 사과 50g(1/3개)', '["오이","다진 땅콩","순두부","사과"]'::jsonb, ARRAY['9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','02c78319-0bf6-45e0-8a7b-7546e1e47ba7','4566cac5-9166-4c0d-906a-bfc7360f8f5b','c85a52b9-c3b4-4a76-951c-bb40edeb3adb']::uuid[], '[{"step":1,"text":"사과, 순두부를 믹서에 넣고 곱게 갈아 소스를 만든다.","imageUrl":null},{"step":2,"text":"오이는 소금으로 문질러 씻어 반을 갈라 씨를 제거하고 어슷썰기를 한다.","imageUrl":null},{"step":3,"text":"썰어 놓은 오이에 순두부사과 소스를 넣고 버무린 후 다진 땅콩을 뿌려 마무리 한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00032_2.png', 75, 10, 4, 2, 22),
  ('33', '사과 새우 북엇국', '국&찌개', '북엇국
북어채 25g(15개), 새우 10g(3마리), 사과 30g(1/5개), 양파 40g(1/4개),
표고버섯 20g(2장), 물 300ml(1½컵)', '["북엇국","북어채","새우","사과","양파","표고버섯","물"]'::jsonb, ARRAY['a6228d2a-6158-4542-bb52-b4f41a06f448','6f10b4ad-53a2-4a07-ba89-19a6b074373d','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','66458b1b-c92f-43fa-8eba-e428892ce88a','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":2,"text":"북어채를 잘게 손으로 찢어 찬물에 헹구어 준비한 후 양파, 표고버섯, 사과는 채 썰고 새우는 등쪽의 두세 마디에 꼬챙이를 넣어 내장을 뺀 후 헹군다.","imageUrl":null},{"step":3,"text":"찬물에 북어채, 새우, 표고버섯, 양파를 넣고 20분 정도 끓인 후 사과를 넣어 북어의 씁쓸한 맛을 없앤다.","imageUrl":null},{"step":5,"text":"그릇에 담아낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00033_2.png', 65, 2, 12, 1, 78),
  ('36', '저염 된장으로 맛을 낸 황태해장국', '국&찌개', '황태해장국
황태(채) 15g(10개), 콩나물 30g(1/6봉지), 무 30g(5×3×2cm), 저염된장 10g(2작은술), 물 300ml(1½컵), 청양고추 5g(1/2개), 다진 마늘 2g(1/3작은술)', '["황태해장국","황태","콩나물","무","저염된장","물","청양고추","다진 마늘"]'::jsonb, ARRAY['a6228d2a-6158-4542-bb52-b4f41a06f448','2db049b2-f39c-47ba-857f-fa02b3b0c610','f80c9a7d-1510-44e2-a82b-28b9f684e191','392236b1-82e9-4e38-bd12-6a53b80bf463','94786475-832c-4f97-aab7-bf6fbbe2236b','30b5d53c-d247-4f04-9b50-c0f728e65cf9','fc6e31ce-388e-45cd-956b-b238b9134eb1']::uuid[], '[{"step":3,"text":"황태는 손질하여 물에 헹궈 건져 놓고 콩나물은 다듬어 씻고 청양고추는 어슷썰기 한다.","imageUrl":null},{"step":4,"text":"냄비에 물을 붓고 황태와 무를 넣고 끓인 후 육수에서 물을 건져내고 저염 된장을 푼다.","imageUrl":null},{"step":5,"text":"콩나물, 다진 마늘, 청양고추를 넣고 뚜껑을 덮어 김이 나게 끓\r\n여준다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00036_2.png', 100, 12, 13, 0, 361),
  ('37', '된장국', '국&찌개', '
두부 20g(2×2×2cm), 애느타리버섯 20g(4가닥), 감자 10g(4×3×1cm), 양파 10g(2×1cm), 대파 10g(5cm), 된장 5g(1작은술), 물 300ml(1½컵)', '["두부","애느타리버섯","감자","양파","대파","된장","물"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','7c91e298-5ace-4242-8619-cdcc80587cd7','20894da1-739d-4d52-b5fe-4943bd3492d5','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','392236b1-82e9-4e38-bd12-6a53b80bf463','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"감자, 양파는 얇게 썰고 애느타리 버섯은 썰어 달궈진 팬에 굽는다.","imageUrl":null},{"step":2,"text":"냄비에 물을 붓고 된장을 푼 뒤 감자, 양파, 두부를 넣어 재료가 투명해지게 끓인 후 된장국의 재료를 건져서 믹서에 넣어 갈고 된장국에 넣어 한번 더 끓인다.","imageUrl":null},{"step":3,"text":"구운 애느타리버섯과 대파를 국에 넣어 끓인 후 그릇에 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00037_2.png', 20, 3, 2, 0, 260),
  ('38', '표고버섯 청경채국', '국&찌개', ' 국물용 멸치 5g(3마리), 다시마 1장(5×1cm), 양파 10g(2×1cm), 표고버섯 기둥, 국간장 5g(1작은술), 물 300ml(1½컵)
, 청경채 20g(1개), 표고버섯 20g(2장), 다진 마늘 2g(1/3작은술)', '["국물용 멸치","다시마","양파","표고버섯 기둥","국간장","물","청경채","표고버섯","다진 마늘"]'::jsonb, ARRAY['dd2eee03-8bbf-44ff-8a7f-ed1443986711','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','f175019d-5a93-4cd4-aabc-e7e79445f15a','94786475-832c-4f97-aab7-bf6fbbe2236b','7ac59c14-e767-4f32-a2e5-d558c1a29dfb','66458b1b-c92f-43fa-8eba-e428892ce88a','fc6e31ce-388e-45cd-956b-b238b9134eb1']::uuid[], '[{"step":1,"text":"찬물에 표고버섯,머리와 내장을 제거한 멸치,\r\n다시마, 양파를 넣어 중간 불에서 10분 정도\r\n끓여 멸치육수를 만든다.","imageUrl":null},{"step":2,"text":"육수의 표고버섯 기둥, 멸치, 다시마, 양파를 건진 후 표고버섯은 편으로 썰고 청경채는 4cm 크기로 썬다.","imageUrl":null},{"step":3,"text":"끓는 육수에 준비한 표고버섯과 청경채를 넣고 국간장으로 간을 한 후 마늘을 넣어 한소끔 끓인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00038_2.png', 45, 7, 2, 1, 2441),
  ('95', '치커리샐러드와 올리브 마늘 소스', '반찬', ' 치커리 30g(10줄기), 적양배추 15g(5×3cm), 양파 10g(2×1cm), 당근 5g(3×1×1cm)
, 올리브유 10g(2작은술), 식초 5g(1작은술), 설탕 5g(1작은술), 마늘 5g(1쪽)', '["치커리","적양배추","양파","당근","올리브유","식초","설탕","마늘"]'::jsonb, ARRAY['1389717e-81e4-4350-96d4-d627d851aa10','fd4254d4-2691-47e1-9367-c2b820ef8d00','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','e38c12a7-43cb-421a-a36e-7ef0d32517fa','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b','fc6e31ce-388e-45cd-956b-b238b9134eb1']::uuid[], '[{"step":1,"text":"올리브유, 식초, 설탕, 다진 마늘을 섞어 거품기로 충분히 저어주어 올리브마늘 드레싱을 만든다.","imageUrl":null},{"step":2,"text":"치커리는 싱싱하게 찬물에 담갔다가 물기를 뺀 후 한입 크기로 자르고, 적양배추, 양파, 당근은 곱게채를 썬다.","imageUrl":null},{"step":3,"text":"접시에 준비한 치커리, 적양배추, 양파, 당근을 담고 올리브마늘 드레싱을 뿌린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00095_2.png', 170, 13, 3, 12, 74),
  ('87', '스트로베리 샐러드', '반찬', '
딸기 70g(7개), 플레인요거트 85g(1개), 양상추 70g(2장), 메추리알 30g(3개), 블루베리 15g(1큰술), 식초 약간, 소금 약간', '["딸기","플레인요거트","양상추","메추리알","블루베리","식초","소금"]'::jsonb, ARRAY['60a7c3e6-e703-4fb0-b5d9-0119a5deab83','bb41a88a-ea2b-4830-876d-91fe7f640296','1389717e-81e4-4350-96d4-d627d851aa10','0697c442-1209-4aa5-931d-722f60cf2c2f','203b7165-14df-4cb6-b165-e4dadf9a3079','6c285c60-022a-4a00-b172-87df97f16a2f','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"찬물이 담긴 냄비에 식초, 소금을 넣고 메추리알을 삶는다. 물이 끓어오르면 5분 정도 더 삶아 찬물에 헹군 후 껍질을 벗기고 반으로 자른다.","imageUrl":null},{"step":2,"text":"딸기를 흐르는 물에 가볍게 씻어 꼭지를 제거한 후 물기를 빼고 반으로 자른다.","imageUrl":null},{"step":3,"text":"양상추는 찬물에 담갔다가 물기를 빼고 한입 크기로 찢은 후 접시에 양상추, 딸기, 블루베리, 메추리알을 담고 플레인요거트를 끼얹는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00087_2.png', 195, 30, 7, 5, 138),
  ('89', '시금치 우유 소스와 그린매쉬드포테이토', '반찬', ' 감자 80g(1/2개), 시금치우유 소스 5g(1작은술), 아몬드 2g(1알), 설탕 2g(1/3작은술), 크랜베리 3g, 치커리 약간
, 시금치 10g, 우유 10g(2작은술)', '["감자","시금치우유 소스","아몬드","설탕","크랜베리","치커리","시금치","우유"]'::jsonb, ARRAY['20894da1-739d-4d52-b5fe-4943bd3492d5','52ba316f-8e7f-415f-8079-9a9d674c9adf','06e6f3e7-0293-469d-a338-11a610f3e71b','1c1e5578-1128-45a4-bcaf-aae79de3639e','1389717e-81e4-4350-96d4-d627d851aa10','9a7f4da6-531b-4478-89ff-d73beafcad1b','e937397f-54e2-49df-997a-f393c58360be']::uuid[], '[{"step":1,"text":"시금치는 끓는 소금물에 데쳐 찬물에 헹구어 물기를 짜고 우유를 넣고 블렌더에 곱게 갈아 체에 거른다.","imageUrl":null},{"step":2,"text":"껍질 벗긴 감자는 찜기에 넣어 20분 정도 삶고 꺼내서 으깨고, 아몬드는 잘게 다지며, 치커리는 곱게 다진다.","imageUrl":null},{"step":3,"text":"으깬 감자, 다진 치커리, 시금치 우유소스, 설탕을 넣고 섞어 접시에 담고 아몬드, 크랜베리를 올리고 시금치우유 소스를 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00089_2.png', 155, 32, 5, 1, 24),
  ('91', '버섯구이와 두부타르타르 소스', '반찬', ' 새송이버섯 70g(7개), 올리브유 10g(2작은술)
, 치커리 10g(3줄기)
, 연두부 30g(1/4모), 다진 양파 10g(2작은술), 다진 오이피클 10g(2작은술), 올리브유 2g(1/3작은술), 식초 5g(1작은술), 레몬즙 3g(2/3작은술), 머스터드 3g(2/3작은술), 꿀 2g(1/3작은술), 흰 후추 약간', '["새송이버섯","올리브유","치커리","연두부","다진 양파","다진 오이피클","식초","레몬즙","머스터드","꿀","흰 후추"]'::jsonb, ARRAY['3f94371a-728f-49ae-8ea9-1a1e87b68048','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','1389717e-81e4-4350-96d4-d627d851aa10','4566cac5-9166-4c0d-906a-bfc7360f8f5b','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','6c285c60-022a-4a00-b172-87df97f16a2f','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','5b59cfae-1277-48af-99a6-833687e2da0b','286d1783-cd34-4aae-ac8b-006529ec8bc5','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"곱게 다진 양파와 오이피클은 물기를 짠다.","imageUrl":null},{"step":2,"text":"연두부에 다진 양파, 다진 오이피클, 올리브유, 머스터드, 후추, 꿀, 식초, 레몬즙을 넣어 두부타르타르 소스를 만든다.","imageUrl":null},{"step":3,"text":"새송이버섯은 0.5cm 두께로 썰고 프라이팬에 노릇하게 구워준 후 접시에 새송이버섯과 치커리를 담고 소스를 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00091_2.png', 150, 18, 8, 5, 133),
  ('93', '구운채소와 간장레몬 소스', '반찬', ' 가지 20g(3cm), 호박 50g(1/3개), 새송이버섯 15g(3개), 양파 15g(1/8개), 발사믹크레마 15g(1큰술), 빨강 파프리카 3g(3×1cm), 노랑 파프리카 3g(3×1cm), 청피망 3g(3×1cm), 올리브유 약간
, 저염간장 5g(1작은술), 식초 15g(1큰술), 설탕 10g(1큰술), 레몬즙 5g(1작은술)', '["가지","호박","새송이버섯","양파","발사믹크레마","빨강 파프리카","노랑 파프리카","청피망","올리브유","저염간장","식초","설탕","레몬즙"]'::jsonb, ARRAY['3e12cf79-2cde-4309-9f7c-4eccce3fde28','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','3f94371a-728f-49ae-8ea9-1a1e87b68048','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','5e79d288-1400-4817-bd20-e5e6041821b1','df459e6f-3515-45d5-8c9a-9d37b6249379','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','f175019d-5a93-4cd4-aabc-e7e79445f15a','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67']::uuid[], '[{"step":1,"text":"저염간장, 식초, 레몬즙, 설탕을 혼합하여 간장레몬 소스를 만든다.","imageUrl":null},{"step":2,"text":"호박, 가지, 새송이버섯은 3cm 길이로 자른 후 얇은 편으로 채 썰고, 양파, 파프리카, 피망은 호박 길이로 썬다.","imageUrl":null},{"step":3,"text":"가지, 호박, 새송이버섯, 양파, 파프리카, 피망에 올리브유를 바르고 달궈진 그릴 팬에 구운 후 접시에 담고 발사믹 크레타를 뿌리고 간장레몬 소스를 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00093_2.png', 175, 19, 4, 9, 38),
  ('94', '브로콜리 컬리플라워 샐러드와 두유 요거트 소스', '반찬', ' 브로콜리 40g(1/5송이), 컬리플라워 40g(1/3송이), 적양파 10g(2×1cm), 강낭콩 5g(1작은술), 건포도 5알, 호두 1/2알, 소금 약간
, 두유 50g(3⅓큰술), 플레인요거트 20g(1⅓큰술), 레몬즙 5g(1작은술), 설탕 약간', '["브로콜리","컬리플라워","적양파","강낭콩","건포도","호두","소금","두유","플레인요거트","레몬즙","설탕"]'::jsonb, ARRAY['9bf64924-ce53-42bb-849e-7294416e95d6','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','1c1e5578-1128-45a4-bcaf-aae79de3639e','7651578f-1206-499d-a04c-15f034d4cae2','2cf0c12b-f248-4012-8f53-303c730a7b3d','a4e9789c-3090-43d8-ab14-e4e168f8b910','bb41a88a-ea2b-4830-876d-91fe7f640296','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"두유에 플레인요거트와 레몬즙, 설탕을 넣고 잘 섞어 두유요거트 소스를 만든다.","imageUrl":null},{"step":2,"text":"강낭콩은 물에 불린 후 콩과 물을 1:2.5로 넣고 20~25분 삶아 건지고 브로콜리와 컬리플라워는 한입 크기로 썰어 끓는 소금물에 살짝 데쳐 찬물에 헹궈 물기를 뺀다.","imageUrl":null},{"step":3,"text":"접시에 데친 브로콜리와 컬리플라워, 삶은 강낭콩, 채썬 적양파, 다진 호두, 건포도를 담고 두유요거트 소스를 곁들여 낸다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00094_2.png', 210, 30, 9, 6, 79),
  ('108', '오렌지와 당근 만남주스', '후식', '오렌지 당근펀치
당근 100g(1/2개), 오렌지 100g(1/2개)', '["오렌지 당근펀치","당근","오렌지"]'::jsonb, ARRAY['e38c12a7-43cb-421a-a36e-7ef0d32517fa','19eb37dc-2b1c-4e89-a931-31a38ae60561']::uuid[], '[{"step":1,"text":"오렌지는 깨끗이 씻어 껍질을 벗긴다.","imageUrl":null},{"step":2,"text":"당근은 깨끗이 씻어 작은 토막으로 썬다.","imageUrl":null},{"step":3,"text":"당근, 오렌지, 물(50ml)을 믹서에 곱게 간다.","imageUrl":null},{"step":4,"text":"믹서에 갈아낸 주스는 고운 체로 거른다.","imageUrl":null},{"step":5,"text":"주스를 살얼음이 생길 만큼 시원하게 냉동한다.","imageUrl":null},{"step":6,"text":"컵에 담아 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00108_1.png', 60, 14, 1, 0, 76),
  ('111', '칠곡석류국수', '일품', ' 소면 160g, 저염소금 4g(1작은술), 식초 8g(1/2작은술)
, 석류 200g(1/2개)
, 잣 4g(1작은술), 아몬드 4g(1작은술), 해바라기씨 4g(1작은술), 호두 4g(1작은술), 호박씨 4g(1작은술), 오이 20g(1/4개)', '["소면","저염소금","식초","석류","잣","아몬드","해바라기씨","호두","호박씨","오이"]'::jsonb, ARRAY['b85df3ba-e324-47fa-b25d-d5bb552b8590','2cf0c12b-f248-4012-8f53-303c730a7b3d','6c285c60-022a-4a00-b172-87df97f16a2f','bbbbd533-8922-4dac-9e4c-cd93ea710c92','52ba316f-8e7f-415f-8079-9a9d674c9adf','7651578f-1206-499d-a04c-15f034d4cae2','3d359f85-dafb-4490-a263-752f436e698b','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a']::uuid[], '[{"step":1,"text":"잣, 아몬드, 해바라기씨, 호두, 호박씨는 다진다.","imageUrl":null},{"step":2,"text":"끓는 물에 저염소금과 식초를 넣은 후 소면을 삶은 후 체에 건져 물기를\r\n뺀다.","imageUrl":null},{"step":3,"text":"석류는 물 600g와 함께 믹서에 갈고 체에 걸러 즙을 낸다. 그릇에 면을 담고 차갑게 식힌 석류즙을 붓고 견과류, 채 썬 오이를 고명으로 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00111_2.png', 73.4, 12.7, 2.1, 1.6, 12.5),
  ('113', '블랙빈 곤약국수', '일품', '실곤약 440g, 검은콩 70g, 볶은 흑임자 6g(1작은술), 호두 6g(1알)
,오이 20g(1/8개), 토마토 50g(1/2개), 달걀 50g(1개)', '["실곤약","검은콩","볶은 흑임자","호두","오이","토마토","달걀"]'::jsonb, ARRAY['54a52322-b4df-4354-a7a5-2a7b0c41f7bd','f82b8382-3b65-4839-9f45-524168f3da07','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','7651578f-1206-499d-a04c-15f034d4cae2','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','c7d438a6-34d6-423f-905d-446b839e2f39']::uuid[], '[{"step":1,"text":"검은콩을 1시간 찬물에 담가 불린 후 삶아 익힌 후 불순물을 제거하고 흑임자, 생수, 삶은 콩, 호두를 믹서에 갈아 살엄음이 생기도록 냉동실에 넣는다.","imageUrl":null},{"step":2,"text":"오이는 돌려 깎아 채 썰고, 토마토는 1/8크기로 썰고, 달걀은 삶아 반으로 자른다.","imageUrl":null},{"step":3,"text":"실곤약은 끓는 물에 데치고 찬물에 헹궈 그릇에 담은 후 콩물을 담고 오이, 토마토, 달걀을 고명으로 올려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00113_2.png', 54.3, 4.9, 3.4, 2.4, 18.5),
  ('114', '닭가슴살 브로콜리 만두', '일품', '주재료
만두피 4g(2장), 브로콜리 100g(1/4개), 숙주 100g, 표고버섯 20g(2개), 닭 가슴살 100g, 참기름 2g(1/2작은술), 저염간장 4g(1작은술), 소금 0.5g, 후춧가루 0.1g', '["주재료","만두피","브로콜리","숙주","표고버섯","닭 가슴살","참기름","저염간장","소금","후춧가루"]'::jsonb, ARRAY['60a99746-3614-4ef6-a3a2-53532e8b61a1','9bf64924-ce53-42bb-849e-7294416e95d6','2647e451-e8f5-4fce-91bd-8beabb2384d8','66458b1b-c92f-43fa-8eba-e428892ce88a','e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','0c0ade94-cfd8-4104-b44c-40e942cac482','f175019d-5a93-4cd4-aabc-e7e79445f15a','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"브로콜리, 숙주, 표고버섯, 닭 가슴살은 다지고 다진 닭 가슴살은 소금과 후추로 밑간 한다.","imageUrl":null},{"step":2,"text":"다진 채소와 닭가슴살, 참기름, 저염간장을 섞어 만두소를 만든다.","imageUrl":null},{"step":3,"text":"준비한 만두피에 만두소를 넣은 후 만두 모양으로 빚고 만두를 찜통에 넣어 찌고 그릇에 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00114_2.png', 123.2, 19, 8.4, 1.5, 167.9),
  ('131', '함초 냉이 국수', '일품', ' 소면 50g
, 함초 3g(1/2작은술), 노루궁뎅이버섯 25g(1/2개), 다시마 17g(15cm), 파 140g(1/2개), 양파 150g(1/2개), 무 250g(1/3개), 모시조개 150g(3/4컵), 냉이 35g, 간장 30g(2큰술)
, 달걀 50g(1개), 청고추 20g(1개), 실고추 2g', '["소면","함초","노루궁뎅이버섯","다시마","파","양파","무","모시조개","냉이","간장","달걀","청고추","실고추"]'::jsonb, ARRAY['b85df3ba-e324-47fa-b25d-d5bb552b8590','2753a03c-9508-458a-9f55-75307de4f7d5','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','4b410642-7bf9-45ad-9055-e7d9a34edaa1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','f80c9a7d-1510-44e2-a82b-28b9f684e191','b6047d76-6c94-4757-b1d1-9175aea0c84a','f175019d-5a93-4cd4-aabc-e7e79445f15a','c7d438a6-34d6-423f-905d-446b839e2f39','30b5d53c-d247-4f04-9b50-c0f728e65cf9']::uuid[], '[{"step":1,"text":"함초, 노루궁뎅이버섯, 다시마, 파, 양파, 무를 물에 넣어 10분 끓이고 향이 강한 모시조개와 냉이를 넣고 30분  끓인 후 간장으로 색을 낸다.","imageUrl":null},{"step":2,"text":"소면은 따로 삶는다.","imageUrl":null},{"step":3,"text":"그릇에 삶은 소면을 담은 후 육수를 붓고 지단, 슬라이스한 청고추, 실고추를 올려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00131_2.png', 35.8, 7.1, 1.8, 0, 34.5),
  ('137', '된장 두부찌개', '국&찌개', '두부 320g(1모), 쌀뜨물 300g(1½컵), 돼지고기 100g, 김치 140g, 된장 20g(1½큰술), 청양고추 10g(1/2개), 홍고추 5g(1/4개),
대파 10g(2cm), 고춧가루 5g(1작은술)', '["두부","쌀뜨물","돼지고기","김치","된장","청양고추","홍고추","대파","고춧가루"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','70e914d4-0d03-4202-8b66-81bd8499aa08','133f214e-50f4-431d-af36-d97f6c9d4f9b','392236b1-82e9-4e38-bd12-6a53b80bf463','30b5d53c-d247-4f04-9b50-c0f728e65cf9','4b410642-7bf9-45ad-9055-e7d9a34edaa1','84104c49-0af4-4323-a56b-b67002a422d9']::uuid[], '[{"step":1,"text":"두부에 쌀뜨물을 넣고 갈아준다.","imageUrl":null},{"step":2,"text":"돼지고기는 썰고 김치는 물에 씻어 양념을 제거하고 3×3cm로 썬다.","imageUrl":null},{"step":3,"text":"냄비에 돼지고기와 김치를 함께 볶은 후, 망에 거른 된장과 1의 두부, 고춧가루, 청양고추, 홍고추를 넣어 끓이다가 대파를 넣어 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00137_2.png', 77.3, 2.4, 7.5, 4.2, 124.6),
  ('138', '부대된장찌개', '국&찌개', '다시마 1g, 두부 10g, 떡국 떡 10g, 스팸(마일드) 10g, 다진 마늘 5g, 무 20g, 김치 15g, 소시지 10g(1/2개), 우민찌 5g(1작은술), 양파 5g, 저염된장 15g(1큰술), 베이컨 5g, 대파 5g, 청양고추 5g, 홍고추 1g', '["다시마","두부","떡국 떡","스팸","다진 마늘","무","김치","소시지","우민찌","양파","저염된장","베이컨","대파","청양고추","홍고추"]'::jsonb, ARRAY['84032a7e-ec18-44d5-ab30-c7b960ca5ca9','4566cac5-9166-4c0d-906a-bfc7360f8f5b','fc6e31ce-388e-45cd-956b-b238b9134eb1','f80c9a7d-1510-44e2-a82b-28b9f684e191','133f214e-50f4-431d-af36-d97f6c9d4f9b','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','392236b1-82e9-4e38-bd12-6a53b80bf463','bd88bfed-198e-4891-9430-06660bdeaa9a','4b410642-7bf9-45ad-9055-e7d9a34edaa1','30b5d53c-d247-4f04-9b50-c0f728e65cf9']::uuid[], '[{"step":1,"text":"김치, 베이컨, 스팸, 소시지, 양파, 두부, 무는 두께 0.5cm로 썬다.","imageUrl":null},{"step":2,"text":"다시마와 물을 끓여 다시마물을 만든다.","imageUrl":null},{"step":3,"text":"냄비에 소시지, 베이컨, 두부, 스팸, 무, 우민찌, 김치, 다시마물 300g을 넣어 끓인 후 저염된장, 양파, 대파, 다진 마늘, 떡국 떡을 넣고 재료가 다 익으면 홍고추와 청양고추를 넣어 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00138_2.png', 72.6, 4.2, 5.3, 3.9, 191.9),
  ('181', '양배추감자전', '반찬', ' 감자 100g(1개), 양배추 150g(1/2개), 당근 15g(1/10개), 두부 20g(1/20모), 돼지고기 30g, 청양고추 5g(1개), 부침가루 45g(3큰술), 달걀 60g(1개), 식용유 15g(1큰술)
, 오렌지즙 15g(1큰술), 간장 2g(1/2작은술), 식초 10g(2작은술)', '["감자","양배추","당근","두부","돼지고기","청양고추","부침가루","달걀","식용유","오렌지즙","간장","식초"]'::jsonb, ARRAY['20894da1-739d-4d52-b5fe-4943bd3492d5','fd4254d4-2691-47e1-9367-c2b820ef8d00','e38c12a7-43cb-421a-a36e-7ef0d32517fa','4566cac5-9166-4c0d-906a-bfc7360f8f5b','70e914d4-0d03-4202-8b66-81bd8499aa08','30b5d53c-d247-4f04-9b50-c0f728e65cf9','aab3b0b9-d346-4697-a1c8-1b1530153788','c7d438a6-34d6-423f-905d-446b839e2f39','a7a59e81-de3d-4893-b56a-b2218732a25b','f175019d-5a93-4cd4-aabc-e7e79445f15a','6c285c60-022a-4a00-b172-87df97f16a2f']::uuid[], '[{"step":1,"text":"감자는 믹서에 갈고 양배추는 채 썰고 고기, 당근, 청양고추, 두부는 다진다.","imageUrl":null},{"step":2,"text":"준비해둔 재료를 모두 섞고 부침가루와 계란을 넣어 반죽한다.","imageUrl":null},{"step":3,"text":"가열된 팬에 기름을 두르고 반죽을 부어 굽고 소스를 함께 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00181_2.png', 148.9, 14.7, 7.7, 6.6, 107.1),
  ('74', '돌나물 샐러드', '반찬', ' 돌나물 90g, 미니새송이버섯 60g(7개), 참기름 약간
, 마요네즈 10g(2작은술), 레몬즙 20g(1⅓큰술), 청양고추 5g(1/2개), 홍고추 5g(1/2개), 참기름 약간', '["돌나물","미니새송이버섯","참기름","마요네즈","레몬즙","청양고추","홍고추"]'::jsonb, ARRAY['0c0ade94-cfd8-4104-b44c-40e942cac482','549c7365-28e9-491f-9040-412558f93a5c','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','30b5d53c-d247-4f04-9b50-c0f728e65cf9']::uuid[], '[{"step":1,"text":"청양고추와 홍고추를 다져서 참기름에 살짝 볶은 후 볶은 고추에 마요네즈와 레몬즙을 넣어 소스를 만든다.","imageUrl":null},{"step":2,"text":"돌나물은 손질하여 찬물에 담구고 새송이버섯은 달군 프라이팬에 참기름을 두르고 노릇\r\n하게 굽는다.","imageUrl":null},{"step":3,"text":"돌나물은 물기를 빼고 구운 새송이버섯과 레몬마요네즈 소스를 넣고\r\n버무려 접시에 담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00074_2.png', 235, 2, 3, 24, 151),
  ('159', '석류 보쌈김치', '반찬', ' 배추 70g(1/10개), 석류즙 10g(2작은술), 소금 5g(1/2작은술)
, 무 10g(3cm), 미나리 10g, 쪽파 10g(1개), 다진 마늘 5g(1작은술), 다진 생강 5g(1작은술), 새우젓국 15g(1큰술)', '["배추","석류즙","소금","무","미나리","쪽파","다진 마늘","다진 생강","새우젓국"]'::jsonb, ARRAY['e116f85b-0eaa-40cb-8107-df5ec8486ad4','2cf0c12b-f248-4012-8f53-303c730a7b3d','f80c9a7d-1510-44e2-a82b-28b9f684e191','dc7b2b73-74de-4fb8-9274-a5967ca444f9','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9']::uuid[], '[{"step":1,"text":"배추를 소금물에 하루 동안 절인 후 물기를 빼고 석류는 즙을 낸다.","imageUrl":null},{"step":2,"text":"무는 채 썰고, 쪽파와 미나리는 4cm로 자른다.","imageUrl":null},{"step":3,"text":"무채, 미나리, 쪽파, 다진 마늘, 다진 생강, 새우젓국을 넣고 섞어 소를 만들고 절인 배추에 소를 넣고 오므려 싼다. 석류즙에 소를 채운 배추를 담가 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00159_2.png', 24.5, 4.7, 1.4, 0, 171.3),
  ('161', '유자 대구조림', '반찬', ' 대구살 120g, 홍파프리카 10g(1/10개), 황파프리카 10g(1/10개),청파프리카 10g(1/10개), 황금팽이버섯 10g, 미나리 20g, 밀가루 25g(2큰술)
, 유자청 20g(1⅓큰술), 발사믹식초 10g(2작은술), 화이트와인 10g(2작은술)
, 대파 30g(1개)', '["대구살","홍파프리카","황파프리카","청파프리카","황금팽이버섯","미나리","밀가루","유자청","발사믹식초","화이트와인","대파"]'::jsonb, ARRAY['5e79d288-1400-4817-bd20-e5e6041821b1','dc7b2b73-74de-4fb8-9274-a5967ca444f9','aab3b0b9-d346-4697-a1c8-1b1530153788','ff5b6cbe-7985-4ca2-94ad-5525717cddf1','6c285c60-022a-4a00-b172-87df97f16a2f','e16eaf50-ebd3-4933-a774-3ce6fc92593f','4b410642-7bf9-45ad-9055-e7d9a34edaa1']::uuid[], '[{"step":1,"text":"발사믹 식초, 화이트와인, 다진 유자청 건더기를 넣고 졸여 소스를 만들고 대구를 손질하여 포를 뜬다.","imageUrl":null},{"step":2,"text":"대파, 청파프리카, 홍파프리카, 황파프리카를 채 썬다.","imageUrl":null},{"step":3,"text":"대구포에 밀가루를 묻혀 청파프리카, 홍파프리카, 황파프리카, 황금팽이버섯을 넣고 말아 미나리로 묶어 찐 후 소스를 뿌리고 썬 대파를 올려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00161_2.png', 84, 10.6, 9.6, 0.4, 109.7),
  ('162', '파프리카 물김치', '반찬', ' 자색고구마 10g(3cm), 무 10g(2cm), 배 80g(1/4개), 배추 200g(1/3개), 부추 10g, 사과 80g(1/3개), 쪽파 10g(10cm), 소금 20g(1⅓큰술)
, 멥쌀 10g(2작은술), 물엿 50g(1/4컵), 황파프리카 140g(1½개)', '["자색고구마","무","배","배추","부추","사과","쪽파","소금","멥쌀","물엿","황파프리카"]'::jsonb, ARRAY['4b4f0113-01cf-4dc6-ae1f-30f09e99746b','f80c9a7d-1510-44e2-a82b-28b9f684e191','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','e116f85b-0eaa-40cb-8107-df5ec8486ad4','058648c3-fd8e-476d-952f-b15dc67f1877','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','4b410642-7bf9-45ad-9055-e7d9a34edaa1','2cf0c12b-f248-4012-8f53-303c730a7b3d','a5bc0b46-0192-496a-b429-d2cb90b2bca9','cc9dea71-6d38-4d4d-a688-f6ade0e7ba0d','5e79d288-1400-4817-bd20-e5e6041821b1']::uuid[], '[{"step":1,"text":"황파프리카를 갈아 체에 내리고 멥쌀로 쌀풀을 만들어 황파프리카 즙을 섞고 물엿을 첨가하여 양념을 만든다.","imageUrl":null},{"step":2,"text":"배추를 소금물에 절이고 절인 배추를 찬물로 씻어 소금기를 뺀다.","imageUrl":null},{"step":3,"text":"소금기를 뺀 배추에 채썬 자색고구마, 무, 쪽파, 부추, 사과, 배를 놓고 양념을 부은 후 3일 동안 숙성시켜 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00162_2.png', 44.9, 10.1, 1.1, 0, 272),
  ('193', '고추장 라따뚜이', '반찬', ' 애호박 70g(1½개), 양송이버섯 60g(3개), 가지 70g(1/2개), 저염살라미 25g, 사과 60g(1/3개)
,양파 40g(1/5개), 마늘 10g(2개), 토마토 600g(3개), 설탕 10g(2작은술), 바질 50g, 고추장 15g(1큰술)', '["애호박","양송이버섯","가지","저염살라미","사과","양파","마늘","토마토","설탕","바질","고추장"]'::jsonb, ARRAY['88c94a13-dc8a-4e66-ab19-08fc2ea82c77','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','3e12cf79-2cde-4309-9f7c-4eccce3fde28','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','06e6f3e7-0293-469d-a338-11a610f3e71b','ba9e5a79-cab3-4af0-942b-0b35fd745150','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb']::uuid[], '[{"step":1,"text":"양파와 마늘은 다져서 볶다가 토마토 과육과 설탕, 바질을 넣고 고추장을 섞어 토마토 소스를 만든다.","imageUrl":null},{"step":2,"text":"가지, 양송이버섯, 애호박, 사과는 썰고 살라미는 데친다.","imageUrl":null},{"step":3,"text":"오븐용 팬에 토마토 소스를 넓게 펴준 뒤 애호박, 가지, 양송이버섯, 살라미를 겹치게 넣고 180℃로 예열한 오븐에 넣고 30분 구워 완성한다","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00193_2.png', 62.6, 7.6, 3.1, 2.2, 138.5),
  ('201', '민들레 샐러드', '반찬', ' 민들레 잎 40g, 비트 5g(1작은술), 오렌지(껍질) 40g(1/5개)
, 간장 20g(1⅓큰술), 다진 홍고추 10g(1개), 레몬즙 60g(4큰술), 설탕 6g(1작은술)', '["민들레 잎","비트","오렌지","간장","다진 홍고추","레몬즙","설탕"]'::jsonb, ARRAY['524e1b82-1f81-4648-b50c-441404a06786','19eb37dc-2b1c-4e89-a931-31a38ae60561','f175019d-5a93-4cd4-aabc-e7e79445f15a','30b5d53c-d247-4f04-9b50-c0f728e65cf9','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"간장, 레몬즙, 설탕, 다진 홍고추를 섞어 드레싱을 만든다.","imageUrl":null},{"step":2,"text":"민들레 잎은 4×4cm로 썰고, 비트는 채 썰고 물에 담가 색을 뺀다.","imageUrl":null},{"step":3,"text":"오렌지는 씻어 껍질만 발라 채 썰고 민들레 잎, 비트, 오렌지 껍질을 섞어 접시에 담고 드레싱을 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00201_2.png', 53.9, 10.9, 2.4, 0, 874.2),
  ('202', '토마토 가지 카프레제', '후식', ' 가지 100g(1개), 토마토 200g(1½개), 무순 20g, 마늘 10g(2개), 올리브오일 5g(1작은술)
, 올리브오일 25g(2큰술), 발사믹식초 60g(4큰술), 후춧가루 2g(1/2작은술)', '["가지","토마토","무순","마늘","올리브오일","발사믹식초","후춧가루"]'::jsonb, ARRAY['3e12cf79-2cde-4309-9f7c-4eccce3fde28','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','f09d1d41-602a-441c-a7bc-520311490ceb','fc6e31ce-388e-45cd-956b-b238b9134eb1','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','6c285c60-022a-4a00-b172-87df97f16a2f','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"올리브오일, 발사믹식초, 후춧가루를 섞어 차게 식혀 드레싱을 만든다.","imageUrl":null},{"step":2,"text":"가지와 토마토는 5mm두께로 썰고 120도 오븐에 20분 구운 후 구운 가지는 물기를 제거한다.","imageUrl":null},{"step":3,"text":"팬에 올리브오일을 두르고 약불에서 채 썬 마늘을 볶다가, 가지를 넣고 구운 후 접시에 토마토, 가지를 번갈아 담고 무순으로 장식하고 드레싱을 곁들인다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00202_2.png', 90.5, 7.4, 1.2, 6.2, 11.3),
  ('636', '우렁된장소스 배추롤', '일품', '돼지고기(50g), 배춧잎(5장), 부추(30g), 쌀(100g), 당근(20g),
