  ('637', '인삼떡갈비', '반찬', '소고기(100g), 돼지고기(100g), 대추(3알), 양파(30g),
마늘(20g), 배(1/4개), 애호박(1/2개), 단호박(1/4개),
파프리카(50g), 인삼(1뿌리), 양송이(5개), 배추잎(5장),
저염간장(20g), 설탕(20g), 소금(0.2g), 후춧가루(0.01g)
두부(50g)', '["소고기","돼지고기","대추","양파","마늘","배","애호박","단호박","파프리카","인삼","양송이","배추잎","저염간장","설탕","소금","후춧가루","두부"]'::jsonb, ARRAY['1c49d1f4-5781-474d-818d-bd7002a4dc0b','70e914d4-0d03-4202-8b66-81bd8499aa08','b371c5d2-f12b-47ee-9a87-26efd09db09d','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','98d652af-a6d6-440c-9653-e22fc5d47d88','5e79d288-1400-4817-bd20-e5e6041821b1','9f4dacdc-b7a6-43f9-ab9b-6a3b28042318','48a4fd5a-e4f6-467b-9e3f-445334e0ee04','f175019d-5a93-4cd4-aabc-e7e79445f15a','06e6f3e7-0293-469d-a338-11a610f3e71b','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','4566cac5-9166-4c0d-906a-bfc7360f8f5b']::uuid[], '[{"step":1,"text":"대추는 돌려 깍아 씨를 제거 하고 곱게\r\n다진다.","imageUrl":null},{"step":2,"text":"다진 소고기와 돼지고기에 대추와 소금\r\n후춧가루를 넣고 치댄다.","imageUrl":null},{"step":3,"text":"애호박과 단호박, 파프리카는\r\n입자있게 썰어 ?에 넣고 잘 치댄다.","imageUrl":null},{"step":4,"text":"양송이는 편으로 썰어 팬에 익히고,\r\n인삼을 뇌두를 자르고 깨끗이 씻어\r\n팬에 볶아 잘게 썰어 ?에 넣는다.","imageUrl":null},{"step":5,"text":"재료가 골고루 섞인 떡갈비를 갈비\r\n모양으로 만든다.","imageUrl":null},{"step":6,"text":"떡갈비를 팬에 굽고, 접시에 배춧잎을\r\n깔고 익힌 양송이를 올리고 떡갈비를\r\n담는다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00637_2.png', 253.3, 15, 26.9, 9.5, 196),
  ('638', '초계탕과 사색곤약', '반찬', '닭고기(1마리), 가시오가피(10g), 대파(20g), 다시마(10g),
