  ('641', '훈제오리가슴살 샐러드', '반찬', '오리고기(훈제오리 가슴살, 150g), 발사믹소스(50g),
양파(30g), 파슬리(5g), 블루베리(20g), 레디쉬(1개)', '["오리고기","발사믹소스","양파","파슬리","블루베리","레디쉬"]'::jsonb, ARRAY['813c3e8f-245d-4007-b9e2-4b135809e9ed','5245db59-9275-49a8-b4cd-0426d7262ae4','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4362c386-a37c-44cd-9254-fafd74712a09','203b7165-14df-4cb6-b165-e4dadf9a3079','f80c9a7d-1510-44e2-a82b-28b9f684e191']::uuid[], '[{"step":1,"text":"훈제오리 가슴살을 슬라이스한다.","imageUrl":null},{"step":2,"text":"슬라이스한 훈제오리는 팬에 굽는다.","imageUrl":null},{"step":3,"text":"양파는 채썰고 찬물에 담근 뒤 건진다.","imageUrl":null},{"step":4,"text":"레디쉬는 채썰고 찬물에 담근 뒤\r\n건진다.","imageUrl":null},{"step":5,"text":"먹기 직전에 발사믹소스를 만든다.","imageUrl":null},{"step":6,"text":"접시에 훈제오리와 양파채, 레디쉬,\r\n블루베리를 담고 발사믹소스를\r\n올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00641_2.png', 261.8, 11.5, 21, 14.6, 636),
  ('642', '훈제오리가슴살크러스트', '반찬', '오리고기(훈제오리 가슴살, 150g), 로즈마리(2g), 오렌지(1개),
새송이버섯(1개), 파슬리(5g), 땅콩(50g), 올리브오일(20g),
유자청(20g), 후춧가루(0.5g', '["오리고기","로즈마리","오렌지","새송이버섯","파슬리","땅콩","올리브오일","유자청","후춧가루("]'::jsonb, ARRAY['813c3e8f-245d-4007-b9e2-4b135809e9ed','722e0bf6-fae4-4bb8-bb95-f7b407b085d7','19eb37dc-2b1c-4e89-a931-31a38ae60561','3f94371a-728f-49ae-8ea9-1a1e87b68048','4362c386-a37c-44cd-9254-fafd74712a09','02c78319-0bf6-45e0-8a7b-7546e1e47ba7','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','ff5b6cbe-7985-4ca2-94ad-5525717cddf1']::uuid[], '[{"step":1,"text":"훈제오리 가슴살은 올리브오일,\r\n로즈마리, 후춧가루로\r\n마리네이드한다.","imageUrl":null},{"step":2,"text":"새송이버섯은 편으로 썰고 팬에\r\n굽는다.","imageUrl":null},{"step":3,"text":"오렌지는 슬라이스로 썬다.","imageUrl":null},{"step":4,"text":"땅콩과 파슬리는 입자있게 다진다.","imageUrl":null},{"step":5,"text":"마리네이드한 오리 고기를 구워 접시에\r\n담는다.","imageUrl":null},{"step":6,"text":"유자청에 땅콩, 파슬리가루를 넣고\r\n소스를 만들고, 구워진 오리고기\r\n사이에 오렌지 슬라이스를 넣고\r\n유자청소스를 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00642_2.png', 250, 13.5, 17.2, 14.1, 352.2),
  ('643', '간장소스를 곁들인 새우전복찜', '반찬', '전복(2개), 새우(3마리), 시금치(30g), 해초(20g),
저염간장(20g), 레몬(1/4개), 설탕(20g), 소금(0.1g),
마늘(10g), 녹말(10g), 식용꽃(60g)', '["전복","새우","시금치","해초","저염간장","레몬","설탕","소금","마늘","녹말","식용꽃"]'::jsonb, ARRAY['5678a9c5-5df5-4a97-8f95-77df12578956','6f10b4ad-53a2-4a07-ba89-19a6b074373d','9a7f4da6-531b-4478-89ff-d73beafcad1b','f175019d-5a93-4cd4-aabc-e7e79445f15a','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','06e6f3e7-0293-469d-a338-11a610f3e71b','2cf0c12b-f248-4012-8f53-303c730a7b3d','fc6e31ce-388e-45cd-956b-b238b9134eb1','6613d1d9-80a2-4ce4-9d3d-647203197e53']::uuid[], '[{"step":1,"text":"전복은 수저로 떼어내어 소금으로 비벼\r\n깨끗이 씻는다.","imageUrl":null},{"step":2,"text":"시금치는 데쳐 다지고, 새우는 껍질을\r\n벗겨 전복, 해초와 함께 다진다.","imageUrl":null},{"step":3,"text":"?번을 잘 섞어 전복 껍질에 넣는다.","imageUrl":null},{"step":4,"text":"찜통에 김이 오르면 속을 채운 전복\r\n껍질을 넣고 약 10분 정도 찐다.","imageUrl":null},{"step":5,"text":"저염간장, 레몬, 설탕, 다진마늘을\r\n넣고 살짝 끓여 소스를 만든다.","imageUrl":null},{"step":6,"text":"간장소스에 전분을 풀어 농도를\r\n맞추고, 전복찜에 여러번 바르고\r\n식용꽃을 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00643_2.png', 119.1, 8.2, 19.2, 1.1, 455.9),
  ('644', '검은콩국수', '일품', '검은콩(200g), 메밀면(120g), 오이(30g), 방울토마토(1개),
땅콩(20g), 잣(10g), 참깨(5g)', '["검은콩","메밀면","오이","방울토마토","땅콩","잣","참깨"]'::jsonb, ARRAY['f82b8382-3b65-4839-9f45-524168f3da07','b85df3ba-e324-47fa-b25d-d5bb552b8590','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','02c78319-0bf6-45e0-8a7b-7546e1e47ba7','bbbbd533-8922-4dac-9e4c-cd93ea710c92','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"검은콩은 깨끗이 씻어 약 12시간 정도\r\n충분히 불린다.","imageUrl":null},{"step":2,"text":"불린 검은콩은 20분 정도 삶아 깨끗이\r\n씻는다.","imageUrl":null},{"step":3,"text":"삶은 검은콩은 믹서기에 곱게 갈아\r\n차갑게 식힌다.","imageUrl":null},{"step":4,"text":"오이는 씨를 제거하고 깨끗이 씻어\r\n채썬다.","imageUrl":null},{"step":5,"text":"물을 끓여 메밀면을 삶고, 찬물에\r\n여러번 헹구어 건져 물기를 뺀다.","imageUrl":null},{"step":6,"text":"메밀면을 그릇에 담고 차가운 콩 국물,\r\n땅콩, 잣, 오이, 방울토마토 및 통깨를\r\n올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00644_2.png', 343.6, 68.1, 11.2, 3, 633.5),
  ('645', '겨자소스로 구운 산마샐러드', '반찬', '산마(100g), 참나물(20g), 돈나물(20g), 토마토(100g),
레디쉬(1개), 어린잎(10g), 저염간장(20g), 식초(10g),
설탕(20g), 겨자가루(10g).', '["산마","참나물","돈나물","토마토","레디쉬","어린잎","저염간장","식초","설탕","겨자가루."]'::jsonb, ARRAY['09065cd3-28cc-4a82-8b3e-5121054c7482','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','f80c9a7d-1510-44e2-a82b-28b9f684e191','bc0ebb76-798a-40fe-be99-557ca2b9a9b4','f175019d-5a93-4cd4-aabc-e7e79445f15a','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"어린잎은 찬물에 담근다.","imageUrl":null},{"step":2,"text":"마는 껍질을 벗겨 동글동글하게 썬다","imageUrl":null},{"step":3,"text":"썰어 놓은 마는 팬에 기름을 살짝\r\n두르고 앞뒤로 굽는다.","imageUrl":null},{"step":4,"text":"참나물, 돈나물, 토마토, 레디쉬는\r\n먹기 좋은 크기로 썬다.","imageUrl":null},{"step":5,"text":"겨자가루는 30℃ 물을 섞어 발효\r\n시킨다.","imageUrl":null},{"step":6,"text":"저염간장에 식초, 설탕, 발효겨자를\r\n넣고 골고루 섞어 소스를 만들고,\r\n접시에 구운 마와 손질한 야채를 넣고\r\n만들어 놓은 소스와 어린잎을 올린다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00645_2.png', 112, 16, 3, 4, 144.8),
  ('271', '닭고기김치찌개', '국&찌개', ' 닭가슴살(60g), 애호박(30g), 미나리(20g), 청양고추(3g), 두부(60g)
김치(120g), 참기름(20g), 느타리버섯(10g), 달걀(50g),다시마(5g), 무(40g), 대파(5g), 양파(10g), 마른 고추(3g), 멸치(10g)
마늘(10g), 청주(10g), 물(300g)', '["닭가슴살","애호박","미나리","청양고추","두부","김치","참기름","느타리버섯","달걀","다시마","무","대파","양파","마른 고추","멸치","마늘","청주","물"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','dc7b2b73-74de-4fb8-9274-a5967ca444f9','30b5d53c-d247-4f04-9b50-c0f728e65cf9','4566cac5-9166-4c0d-906a-bfc7360f8f5b','133f214e-50f4-431d-af36-d97f6c9d4f9b','0c0ade94-cfd8-4104-b44c-40e942cac482','7c91e298-5ace-4242-8619-cdcc80587cd7','c7d438a6-34d6-423f-905d-446b839e2f39','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','f80c9a7d-1510-44e2-a82b-28b9f684e191','4b410642-7bf9-45ad-9055-e7d9a34edaa1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','dd2eee03-8bbf-44ff-8a7f-ed1443986711','fc6e31ce-388e-45cd-956b-b238b9134eb1','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"육수 재료를 넣고 중간 불로 끓인 뒤\r\n체에 걸러 육수를 만든다.","imageUrl":null},{"step":2,"text":"닭가슴살은 채 썬 뒤 물에 넣고\r\n삶는다.","imageUrl":null},{"step":3,"text":"애호박은 반달 썰고, 미나리는 5㎝\r\n길이로 썰고, 청양고추는 잘게 썬 뒤\r\n찬물에 담가 씨를 빼고, 두부는 한입\r\n크기로 썰어 물에 담가둔다.","imageUrl":null},{"step":4,"text":"김치를 한입 크기로 썬 뒤 참기름에\r\n볶다가 육수를 붓는다.","imageUrl":null},{"step":5,"text":"두부, 애호박, 느타리버섯, 미나리,\r\n닭가슴살을 넣어 끓어오르면\r\n달걀물과 청양고추를 넣고 조금\r\n더 끓여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00271_2.png', 277.1, 1.79, 5.87, 2.73, 776.6),
  ('272', '완자김치찌개', '국&찌개', ' 콩나물(30g), 김치(50g)
두부(40g), 붉은 고추(15g),돼지고기(등심, 60g), 새우젓(5g),대파(10g), 마늘(5g), 쇠고기(50g)', '["콩나물","김치","두부","붉은 고추","돼지고기","새우젓","대파","마늘","쇠고기"]'::jsonb, ARRAY['2db049b2-f39c-47ba-857f-fa02b3b0c610','133f214e-50f4-431d-af36-d97f6c9d4f9b','4566cac5-9166-4c0d-906a-bfc7360f8f5b','30b5d53c-d247-4f04-9b50-c0f728e65cf9','70e914d4-0d03-4202-8b66-81bd8499aa08','8f2077de-dbd0-4372-a4c2-f987388f16b3','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','1c49d1f4-5781-474d-818d-bd7002a4dc0b']::uuid[], '[{"step":1,"text":"대파, 마늘, 쇠고기를 물(300g)과\r\n함께 끓인 뒤 면포에 걸러 육수를\r\n만든다.","imageUrl":null},{"step":2,"text":"콩나물, 김치를 물에 씻어 손질한다.","imageUrl":null},{"step":3,"text":"두부는 물기를 빼고, 붉은 고추는\r\n다진 뒤 돼지고기와 섞어 반죽해\r\n동그랗게 빚어 완자를 만든다.","imageUrl":null},{"step":4,"text":"김 오른 찜기에 완자를 넣어 찐다.","imageUrl":null},{"step":5,"text":"육수를 끓이고 끓어오르면 김치,\r\n콩나물, 새우젓을 넣는다.","imageUrl":null},{"step":6,"text":"한소끔 더 끓이다가 완자를 넣고\r\n조금 더 끓여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00272_2.png', 161.1, 1.34, 6.78, 2.61, 355),
  ('273', '백김치콩비지찌개', '국&찌개', ' 풋고추(10g), 백김치(100g), 콩비지(100g),참기름(8g), 후춧가루(0.2g), 다진 마늘(10g), 간장(2g)', '["풋고추","백김치","콩비지","참기름","후춧가루","다진 마늘","간장"]'::jsonb, ARRAY['30b5d53c-d247-4f04-9b50-c0f728e65cf9','133f214e-50f4-431d-af36-d97f6c9d4f9b','0c0ade94-cfd8-4104-b44c-40e942cac482','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','fc6e31ce-388e-45cd-956b-b238b9134eb1','f175019d-5a93-4cd4-aabc-e7e79445f15a']::uuid[], '[{"step":1,"text":"풋고추는 잘게 다진다.","imageUrl":null},{"step":2,"text":"백김치는 먹기 좋은 크기로 썬다.","imageUrl":null},{"step":3,"text":"냄비에 백김치를 볶다가 김치가\r\n익으면 참기름, 후춧가루,\r\n다진 마늘을 넣고 볶는다.","imageUrl":null},{"step":4,"text":"물(200g)을 넣고 끓인다.","imageUrl":null},{"step":5,"text":"물이 끓으면 콩비지와 간장,\r\n풋고추를 넣어 약한 불에서 15분\r\n정도 끓여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00273_2.png', 195.3, 3.13, 2.99, 2.99, 447.2),
  ('274', '오징어김치찌개', '국&찌개', ' 오징어(100g), 두부(50g), 팽이버섯(20g), 붉은 고추(4g)
고구마(30g), 콩나물(20g), 김치(140g), 쑥갓(20g),무(50g), 다시마(5g), 대파(20g), 멸치(10g), 물(300g),참기름(10g), 들깻가루(5g)', '["오징어","두부","팽이버섯","붉은 고추","고구마","콩나물","김치","쑥갓","무","다시마","대파","멸치","물","참기름","들깻가루"]'::jsonb, ARRAY['4d148f68-08e0-4599-8953-595db492bf23','4566cac5-9166-4c0d-906a-bfc7360f8f5b','cafedf96-06e9-46a2-a6e2-6cf6f6b15e70','30b5d53c-d247-4f04-9b50-c0f728e65cf9','4b4f0113-01cf-4dc6-ae1f-30f09e99746b','2db049b2-f39c-47ba-857f-fa02b3b0c610','133f214e-50f4-431d-af36-d97f6c9d4f9b','10ccd1c9-12d7-4075-b2cc-bfc87ce891b6','f80c9a7d-1510-44e2-a82b-28b9f684e191','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','4b410642-7bf9-45ad-9055-e7d9a34edaa1','dd2eee03-8bbf-44ff-8a7f-ed1443986711','94786475-832c-4f97-aab7-bf6fbbe2236b','0c0ade94-cfd8-4104-b44c-40e942cac482','184687ba-0cba-4fec-bb21-33fe300c2073']::uuid[], '[{"step":1,"text":"육수 재료를 넣고 끓인 뒤 체로 걸러\r\n육수를 낸다.","imageUrl":null},{"step":2,"text":"오징어 몸통은 큼지막하게 썰고\r\n다리는 얇게 썬다.","imageUrl":null},{"step":3,"text":"두부와 버섯은 먹기 좋게 썰고,\r\n고추는 어슷하게 썰고, 고구마는\r\n먹기 좋은 크기로 썰고, 콩나물은\r\n다듬는다.","imageUrl":null},{"step":4,"text":"김치는 먹기 좋은 크기로 썬 뒤\r\n냄비에 참기름을 두르고 볶다가\r\n고구마, 콩나물, 육수를 넣고 끓인다.","imageUrl":null},{"step":5,"text":"자작하게 끓으면 오징어를 넣고\r\n끓이고, 오징어가 익으면 들깻가루를\r\n넣고 끓인다.","imageUrl":null},{"step":6,"text":"두부, 팽이버섯, 쑥갓, 고구마,\r\n붉은 고추를 넣고 끓여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00274_2.png', 159.1, 2.5, 2.4, 0.7, 549),
  ('275', '해물김치찌개', '국&찌개', ' 주꾸미(40g), 김치(40g), 무(10g), 마늘(3g), 대파(3g), 양파(10g), 두부(10g), 참기름(3g), 배즙(10g), 팽이버섯(3g)
, 다시마(5g), 멸치(10g), 물(300g)', '["주꾸미","김치","무","마늘","대파","양파","두부","참기름","배즙","팽이버섯","다시마","멸치","물"]'::jsonb, ARRAY['c3f77c6a-2dd2-4592-875f-0aa74771d6d0','133f214e-50f4-431d-af36-d97f6c9d4f9b','f80c9a7d-1510-44e2-a82b-28b9f684e191','fc6e31ce-388e-45cd-956b-b238b9134eb1','4b410642-7bf9-45ad-9055-e7d9a34edaa1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4566cac5-9166-4c0d-906a-bfc7360f8f5b','0c0ade94-cfd8-4104-b44c-40e942cac482','eccf67f1-41f0-4a25-b238-6b9e7332c9e1','cafedf96-06e9-46a2-a6e2-6cf6f6b15e70','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','dd2eee03-8bbf-44ff-8a7f-ed1443986711','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"냄비에 육수 재료를 넣고 끓이다가 물이 끓어오르면 다시마를 건지고 조금 더 끓여 육수를 우려낸다.","imageUrl":null},{"step":2,"text":"주꾸미는 내장과 입, 눈을 제거하고 4cm 크기로 잘라 준비한다.","imageUrl":null},{"step":3,"text":"김치는 국물을 꽉 짜서 한입 크기로 썰고, 무는 편 썰고, 마늘은 다지고, 대파는 어슷 썰고, 양파는 굵게 채 썰고, 두부는 납작하게 썬다.","imageUrl":null},{"step":4,"text":"냄비에 참기름을 두르고, 김치, 무, 양파가 투명해질 때까지 볶다가 육수를 붓고 끓으면 주꾸미, 다진 마늘을 넣어 더 끓인다.","imageUrl":null},{"step":5,"text":"김칫국물과 배즙을 2:1로 섞은 뒤 찌개에 넣어 간을 맞춘다.","imageUrl":null},{"step":6,"text":"두부, 팽이버섯을 넣고 한소끔 끓여 마무리한다","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306022845_1678080525384.jpg', 53.9, 5.2, 3, 2.3, 385.1),
  ('276', '맑은부대찌개', '국&찌개', ' 느타리버섯(10g), 두부(50g), 콩나물(10g)
배추(40g), 미나리(20g), 돼지고기(50g)
쇠고기(50g), 불린 당면(10g), 조랭이떡(30g),다시마(3g), 양파(30g), 대파(20g)
