  ('278', '삼계부대찌개', '국&찌개', ' 닭가슴살(100g), 당근(20g), 붉은 고추(6g)
풋고추(6g), 대파(6g), 쑥갓(4g), 표고버섯(14g)
애호박(60g), 김치(40g), 팽이버섯(40g)
당면(21g), 숙주(40g), 떡(40g),당귀(10g), 대추(20g), 오가피(30g), 함초(20g),겨자가루(5g), 고춧가루(20g), 콩가루(5g), 쌀겨(5g), 다진 마늘(3g)', '["닭가슴살","당근","붉은 고추","풋고추","대파","쑥갓","표고버섯","애호박","김치","팽이버섯","당면","숙주","떡","당귀","대추","오가피","함초","겨자가루","고춧가루","콩가루","쌀겨","다진 마늘"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','e38c12a7-43cb-421a-a36e-7ef0d32517fa','30b5d53c-d247-4f04-9b50-c0f728e65cf9','4b410642-7bf9-45ad-9055-e7d9a34edaa1','10ccd1c9-12d7-4075-b2cc-bfc87ce891b6','66458b1b-c92f-43fa-8eba-e428892ce88a','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','133f214e-50f4-431d-af36-d97f6c9d4f9b','cafedf96-06e9-46a2-a6e2-6cf6f6b15e70','b85df3ba-e324-47fa-b25d-d5bb552b8590','2647e451-e8f5-4fce-91bd-8beabb2384d8','af336608-1eeb-4b10-9a3a-1df0ad140ccb','b371c5d2-f12b-47ee-9a87-26efd09db09d','2753a03c-9508-458a-9f55-75307de4f7d5','5b59cfae-1277-48af-99a6-833687e2da0b','84104c49-0af4-4323-a56b-b67002a422d9','c1a987ee-fe94-4eb5-b3e7-d41c23cd3445','fc6e31ce-388e-45cd-956b-b238b9134eb1']::uuid[], '[{"step":1,"text":"육수 재료를 넣고 20분간 끓여\r\n육수를 낸다.","imageUrl":null},{"step":2,"text":"닭가슴살과 당근을 다져 모양을\r\n잡은 뒤 김 오른 찜기에 넣고 찐다.","imageUrl":null},{"step":3,"text":"고추, 대파는 어슷 썰고, 쑥갓,\r\n표고버섯, 애호박, 김치는 먹기\r\n좋은 크기로 썰고, 팽이버섯은\r\n밑동을 잘라 손질한다.","imageUrl":null},{"step":4,"text":"당면과 숙주는 뜨거운 물에 데쳐\r\n준비한다.","imageUrl":null},{"step":5,"text":"양념장 재료를 섞은 뒤 육수(13g)를\r\n넣고 양념장을 만든다.","imageUrl":null},{"step":6,"text":"준비한 재료를 담고 육수를 부은 뒤\r\n양념장을 넣고 끓여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00278_2.png', 299.9, 8.26, 4.46, 0.09, 163.6),
  ('279', '쑥갓부대찌개', '국&찌개', ' 통조림 햄(30g), 애호박(20g), 두부(20g), 팽이버섯(20g), 청양고추(5g), 김치(30g), 쑥갓(4g)
, 다시마(5g), 물(200g)
, 설탕(0.5g), 고춧가루(4g), 다진마늘(2g), 고추장(2g)', '["통조림 햄","애호박","두부","팽이버섯","청양고추","김치","쑥갓","다시마","물","설탕","고춧가루","다진마늘","고추장"]'::jsonb, ARRAY['88c94a13-dc8a-4e66-ab19-08fc2ea82c77','4566cac5-9166-4c0d-906a-bfc7360f8f5b','cafedf96-06e9-46a2-a6e2-6cf6f6b15e70','30b5d53c-d247-4f04-9b50-c0f728e65cf9','133f214e-50f4-431d-af36-d97f6c9d4f9b','10ccd1c9-12d7-4075-b2cc-bfc87ce891b6','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','94786475-832c-4f97-aab7-bf6fbbe2236b','06e6f3e7-0293-469d-a338-11a610f3e71b','84104c49-0af4-4323-a56b-b67002a422d9','fc6e31ce-388e-45cd-956b-b238b9134eb1','84b8828b-7396-4dcb-a5d6-44e3cd5a8fdb']::uuid[], '[{"step":1,"text":"통조림 햄을 썰어 끓는 물에 데친다.","imageUrl":null},{"step":2,"text":"애호박은 반달모양으로 썰고, 두부는 도톰하게 썰고, 팽이버섯은 3등분하고, 청양고추는 어슷 썬다.","imageUrl":null},{"step":3,"text":"김치는 씻어서 잘게 썬다.","imageUrl":null},{"step":4,"text":"양념장을 만든다.","imageUrl":null},{"step":5,"text":"냄비에 물과 다시마를 넣고 살짝 끓여 육수를 만든다.","imageUrl":null},{"step":6,"text":"육수에 손질한 재료를 담고 양념장의 1/2 분량을 넣고 중간 불에 끓이다가 쑥갓과 남은 양념장을 넣고 약한 불에 조금 더 끓여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308012547_1678249547987.jpg', 126.3, 9.9, 6.4, 6.8, 347.1),
  ('280', '들깨순두부찌개', '국&찌개', ' 굴(40g), 멸치(2g), 표고버섯(10g), 느타리버섯(40g), 무(20g)
양파(10g), 미나리(10g), 대파(3g), 붉은 고추(2g), 순두부(100g),다진 마늘(1g), 들깻가루(10g), 국간장(1.5g), 소금(0.5g)', '["굴","멸치","표고버섯","느타리버섯","무","양파","미나리","대파","붉은 고추","순두부","다진 마늘","들깻가루","국간장","소금"]'::jsonb, ARRAY['842f1298-903f-48e9-93bf-41bd90abfa9a','dd2eee03-8bbf-44ff-8a7f-ed1443986711','66458b1b-c92f-43fa-8eba-e428892ce88a','7c91e298-5ace-4242-8619-cdcc80587cd7','f80c9a7d-1510-44e2-a82b-28b9f684e191','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','dc7b2b73-74de-4fb8-9274-a5967ca444f9','4b410642-7bf9-45ad-9055-e7d9a34edaa1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','4566cac5-9166-4c0d-906a-bfc7360f8f5b','fc6e31ce-388e-45cd-956b-b238b9134eb1','184687ba-0cba-4fec-bb21-33fe300c2073','f175019d-5a93-4cd4-aabc-e7e79445f15a','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"굴은 깨끗이 씻은 뒤 김 오른 찜기에\r\n찐다.","imageUrl":null},{"step":2,"text":"굴을 쪄낸 물(250g)에 멸치,\r\n표고버섯 밑동을 넣고 끓인 뒤\r\n멸치와 표고버섯 밑동을 건져내\r\n육수를 만든다.","imageUrl":null},{"step":3,"text":"느타리버섯은 밑동을 제거한 후\r\n씻어 세로로 찢고, 표고버섯은\r\n0.5㎝ 두께로 썬다.","imageUrl":null},{"step":4,"text":"무는 나박 썰고 양파는 채 썰고,\r\n미나리는 3㎝ 길이로 썰고,\r\n대파와 고추는 송송 썬다.","imageUrl":null},{"step":5,"text":"육수에 굴, 다진 마늘, 무, 양파,\r\n버섯을 넣고 끓인다.","imageUrl":null},{"step":6,"text":"들깻가루와 순두부를 넣고 한소끔\r\n끓인 뒤 국간장과 소금으로 간을\r\n맞추고 대파, 붉은 고추, 미나리를\r\n올려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00280_2.png', 171.7, 2.92, 2.8, 1.36, 111.6),
  ('281', '백태순두부찌개', '국&찌개', ' 콩(백태, 30g), 느타리버섯(10g), 표고버섯(10g), 애호박(20g)
양파(10g), 대파(5g), 붉은 고추(2g), 풋고추(2g), 바지락(30g)
저염된장(10g), 새우(25g), 순두부(120g),마른 다시마(1g), 멸치(1g), 물(250g)', '["콩","느타리버섯","표고버섯","애호박","양파","대파","붉은 고추","풋고추","바지락","저염된장","새우","순두부","마른 다시마","멸치","물"]'::jsonb, ARRAY['f82b8382-3b65-4839-9f45-524168f3da07','7c91e298-5ace-4242-8619-cdcc80587cd7','66458b1b-c92f-43fa-8eba-e428892ce88a','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','b6047d76-6c94-4757-b1d1-9175aea0c84a','392236b1-82e9-4e38-bd12-6a53b80bf463','6f10b4ad-53a2-4a07-ba89-19a6b074373d','4566cac5-9166-4c0d-906a-bfc7360f8f5b','dd2eee03-8bbf-44ff-8a7f-ed1443986711','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"냄비에 육수 재료를 넣어 끓인다.","imageUrl":null},{"step":2,"text":"콩을 충분히 불려 믹서기에 물을\r\n넣고 갈아 준비한다.","imageUrl":null},{"step":3,"text":"느타리버섯은 찢고, 표고버섯은 먹기\r\n좋은 크기로 자르고, 애호박과\r\n양파는 깍둑 썰고, 대파와 고추는\r\n송송 썬다.","imageUrl":null},{"step":4,"text":"바지락은 해감해 준비한다.","imageUrl":null},{"step":5,"text":"육수에 콩, 느타리버섯, 표고버섯,\r\n애호박, 저염된장, 새우, 바지락을\r\n넣고 끊인다.","imageUrl":null},{"step":6,"text":"순두부를 넣고 끊인 후 양파, 대파,\r\n붉은 고추, 풋고추를 넣고 한소끔\r\n끓여 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00281_2.png', 165.4, 2.4, 3.08, 1.13, 640.3),
  ('282', '버섯순두부찌개', '국&찌개', ' 표고버섯(3g), 애호박(10g), 감자(10g), 양파(3g), 미나리(3g), 부추(1g), 대파(1g), 청양고추(1g), 순두부(100g)
, 다시마(3g), 표고버섯 밑동(3g), 물(250g)
, 저염된장(5g), 찹쌀가루(3g), 다진마늘(1g), 들깻가루(7g), 저염국간장(1g)', '["표고버섯","애호박","감자","양파","미나리","부추","대파","청양고추","순두부","다시마","표고버섯 밑동","물","저염된장","찹쌀가루","다진마늘","들깻가루","저염국간장"]'::jsonb, ARRAY['66458b1b-c92f-43fa-8eba-e428892ce88a','88c94a13-dc8a-4e66-ab19-08fc2ea82c77','20894da1-739d-4d52-b5fe-4943bd3492d5','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','dc7b2b73-74de-4fb8-9274-a5967ca444f9','058648c3-fd8e-476d-952f-b15dc67f1877','4b410642-7bf9-45ad-9055-e7d9a34edaa1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','4566cac5-9166-4c0d-906a-bfc7360f8f5b','84032a7e-ec18-44d5-ab30-c7b960ca5ca9','94786475-832c-4f97-aab7-bf6fbbe2236b','392236b1-82e9-4e38-bd12-6a53b80bf463','4cb11562-015f-4ab5-969f-0ea8483a0b42','fc6e31ce-388e-45cd-956b-b238b9134eb1','184687ba-0cba-4fec-bb21-33fe300c2073']::uuid[], '[{"step":1,"text":"표고버섯은 머리와 밑동을 분리하고, 머리 부분은 잘게 썬다.","imageUrl":null},{"step":2,"text":"애호박, 감자, 양파는 한입 크기로 썰고, 미나리와 부추는 3cm 길이로 썰고, 대파와 청양고추는 송송 썬다.","imageUrl":null},{"step":3,"text":"물에 다시마, 표고버섯 밑동을 넣고 끓으면 건더기를 건져 육수를 만든다.","imageUrl":null},{"step":4,"text":"육수에 저염된장과 찹쌀가루를 풀어 한소끔 끓이고, 감자와 다진마늘을 넣어 끓인다.","imageUrl":null},{"step":5,"text":"애호박과 표고버섯을 넣고, 순두부, 양파, 들깻가루, 저염국간장을 넣어 한소끔 끓인다.","imageUrl":null},{"step":6,"text":"대파, 청양고추, 미나리, 부추를 듬뿍 올려 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230308/20230308053608_1678264568602.jpg', 85.7, 6.3, 6.4, 3.9, 243.1),
  ('283', '토란순두부찌개', '국&찌개', ' 토란(40g), 표고버섯(20g), 붉은 고추(1g), 청양고추(2g)
백합(150g), 들깻가루(40g), 순두부(150g)', '["토란","표고버섯","붉은 고추","청양고추","백합","들깻가루","순두부"]'::jsonb, ARRAY['66458b1b-c92f-43fa-8eba-e428892ce88a','30b5d53c-d247-4f04-9b50-c0f728e65cf9','184687ba-0cba-4fec-bb21-33fe300c2073','4566cac5-9166-4c0d-906a-bfc7360f8f5b']::uuid[], '[{"step":1,"text":"토란은 2×2㎝로 썬다.","imageUrl":null},{"step":2,"text":"표고버섯은 채 썰고, 고추는\r\n어슷하게 썬다.","imageUrl":null},{"step":3,"text":"냄비에 물(500ml)을 넣고 물이\r\n끓으면 백합을 넣고 끓여 육수를\r\n낸다.","imageUrl":null},{"step":4,"text":"조개가 입을 벌리면 토란과\r\n들깻가루, 표고버섯을 넣고 끓인다.","imageUrl":null},{"step":5,"text":"육수가 어느 정도 걸쭉해지면\r\n순두부를 넣고 끓인다.","imageUrl":null},{"step":6,"text":"붉은 고추와 청양고추를 올려\r\n마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00283_2.png', 312.7, 2.93, 3.48, 2.96, 409.2),
  ('385', '토마토스프파스타', '일품', '홀토마토 200g, 토마토 100g, 다진양파 30g, 다진마늘 20g, 먹물파스타 25g, 치즈 25g
파슬리가루 1g, 함초소금 1g, 올리브오일 30g
곁들이 야채 : 양파 20g, 가지 20g, 2가지색 파프리카 20g, 애호박 20g', '["홀토마토","토마토","다진양파","다진마늘","먹물파스타","치즈","파슬리가루","함초소금","올리브오일","곁들이 야채 : 양파","가지","애호박"]'::jsonb, ARRAY['aa597bcd-596b-4cbe-a2c4-3da0d060cb50','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1','4e0e50d8-ce94-4636-82f5-5bd5ac15d74c','4362c386-a37c-44cd-9254-fafd74712a09','2cf0c12b-f248-4012-8f53-303c730a7b3d','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','3e12cf79-2cde-4309-9f7c-4eccce3fde28','88c94a13-dc8a-4e66-ab19-08fc2ea82c77']::uuid[], '[{"step":1,"text":"토마토홀과 토마토는 송송 다져주고, 마늘,\r\n양파를 냄비에서 볶은 후 믹서에 갈아 토마토\r\n스프를 만들어준다.","imageUrl":null},{"step":2,"text":"만들어진 스프를 볶아서 신맛을 날려준다.","imageUrl":null},{"step":3,"text":"먹물파스타면은 삶은 뒤 오일에 버무려주고\r\n볶아준다.","imageUrl":null},{"step":4,"text":"양파, 애호박, 가지, 2가지색 파프리카를 먹기\r\n좋게 잘라 팬에 볶아준다.","imageUrl":null},{"step":5,"text":"접시에 볶아진 채소와 파스타면을 서로 다시\r\n볶아준다.","imageUrl":null},{"step":6,"text":"치즈를 곱게 다져주고 접시에 파스타면을\r\n올린 뒤, 토마토스프와 치즈가루를 뿌려 완성\r\n한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00385_2.png', 282.6, 37, 10.4, 10.4, 41.4),
  ('386', '다이어트국수', '일품', '실곤약 200g, 물김치국물 200g, 오이 25g, 달걀 1개(60g)
