  ('391', '토마토소고기장조림', '반찬', '소고기 우둔살 200g, 메추리알 100g, 방울토마토 100g, 마늘 30g, 꽈리고추 50g, 양파 45g
양념장 : 맛간장 30g, 흰후추 1g, 어간장 15g, 설탕 15g', '["소고기 우둔살","메추리알","방울토마토","마늘","꽈리고추","양파","양념장 : 맛간장","흰후추","어간장","설탕"]'::jsonb, ARRAY['0697c442-1209-4aa5-931d-722f60cf2c2f','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','fc6e31ce-388e-45cd-956b-b238b9134eb1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','f175019d-5a93-4cd4-aabc-e7e79445f15a','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"소고기는 사방 2cm 정도의 크기로 잘라서\r\n물에서 80% 정도까지 익혀준 후 냉수에\r\n깨끗하게 세척해 준다.","imageUrl":null},{"step":2,"text":"양파는 먹기 좋게 자르고 물 400g과 함께\r\n간장 물을 만들어준다.","imageUrl":null},{"step":3,"text":"간장 물에 데쳐 놓은 소고기부터 졸여주기\r\n시작한다.","imageUrl":null},{"step":4,"text":"메추리알을 넣고 함께 졸여준다.","imageUrl":null},{"step":5,"text":"방울토마토, 양파, 마늘, 꽈리고추까지 넣고\r\n마지막으로 졸여준다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00391_2.png', 282.6, 20.4, 31.2, 8.5, 941.7),
  ('392', '토마토소고기찜', '반찬', '소고기우둔살 200g, 샐러리 40g, 당근 30g, 양파 50g
