  ('394', '삼겹살꼬치구이', '반찬', '삼겹살 200g, 방울토마토 100g, 마늘기름 15g, 후추 1g, 로즈마리 1g, 통후추 2g
대파 20g, 마늘 10g, 꽈리고추 25g
대파채 : 대파 25g, 고춧가루 1g, 레몬즙 2g', '["삼겹살","방울토마토","마늘기름","후추","로즈마리","통후추","대파","마늘","꽈리고추","대파채 : 대파","고춧가루","레몬즙"]'::jsonb, ARRAY['70e914d4-0d03-4202-8b66-81bd8499aa08','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','34302eb3-407c-41e6-b9ae-89f6123f4b65','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','722e0bf6-fae4-4bb8-bb95-f7b407b085d7','4b410642-7bf9-45ad-9055-e7d9a34edaa1','fc6e31ce-388e-45cd-956b-b238b9134eb1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','84104c49-0af4-4323-a56b-b67002a422d9','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67']::uuid[], '[{"step":1,"text":"삼겹살은 길이로 잘라서 마늘기름, 통후추,\r\n로즈마리에 마리네이드 해준다.","imageUrl":null},{"step":2,"text":"대파는 흰 부분만 잘라 구워주고, 꽈리고추도\r\n함께 구워준다.","imageUrl":null},{"step":3,"text":"대파는 가늘게 채 썰어 물에 담가준다.","imageUrl":null},{"step":4,"text":"물에 담가진 대파를 물기를 빼고 양념해준다.","imageUrl":null},{"step":5,"text":"삼겹살을 꼬치에 끼워 굽고 구워진 채소,\r\n대파채와 함께 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00394_2.png', 289.5, 805, 11.2, 23.4, 59.8),
  ('395', '새우아욱죽', '밥', '귀리밥 100g, 아욱 30g, 건새우 25g, 칵테일새우 25g, 저염 된장 30g', '["귀리밥","아욱","건새우","칵테일새우","저염 된장"]'::jsonb, ARRAY['c15a4a69-31ab-450d-943a-2a7bb2230857','6f10b4ad-53a2-4a07-ba89-19a6b074373d','392236b1-82e9-4e38-bd12-6a53b80bf463']::uuid[], '[{"step":1,"text":"저염 된장을 물 300cc에 풀어준 뒤 건새우를\r\n담가 30분 정도 담가준 뒤 살짝 끓여준다.","imageUrl":null},{"step":2,"text":"새우를 풀어준 된장 물을 체에 걸러준다.","imageUrl":null},{"step":3,"text":"아욱은 뜨거운 물에 데쳐서 먹기 좋게 썬다.","imageUrl":null},{"step":4,"text":"냄비에 밥과 된장 물을 풀어 끓인다.","imageUrl":null},{"step":5,"text":"어느 정도 끓으면 칵테일새우와 건져 놓았던\r\n새우를 다시 넣어준다.","imageUrl":null},{"step":6,"text":"불을 끄기 전에 아욱을 넣어 한 번 더 끓여준\r\n후 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00395_2.png', 201.3, 34, 13.1, 1.4, 471.6),
  ('396', '까르보나라뇨끼', '일품', '감자 220g, 깻잎 10g, 베이컨 25g, 백일송이 25g
다진마늘 15g, 다진양파 25g, 다진대파 25g, 흰후추 3g, 버터15g, 우유 200g
생크림 30g, 설탕 10g, 치즈가루 15g', '["감자","깻잎","베이컨","백일송이","다진마늘","다진양파","다진대파","흰후추","버터","우유","생크림","설탕","치즈가루"]'::jsonb, ARRAY['20894da1-739d-4d52-b5fe-4943bd3492d5','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','bd88bfed-198e-4891-9430-06660bdeaa9a','fc6e31ce-388e-45cd-956b-b238b9134eb1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','7aabd532-361f-4240-aa33-6bfa1be4bc4e','e937397f-54e2-49df-997a-f393c58360be','af187077-b7f6-4b0e-9e99-f844f6359ac2','06e6f3e7-0293-469d-a338-11a610f3e71b','4e0e50d8-ce94-4636-82f5-5bd5ac15d74c']::uuid[], '[{"step":1,"text":"감자를 슬라이스 하여 찜통에 찐 후 체에\r\n으깬다. 깻잎을 잘게 채 썰어서 냉수에 담가\r\n향을 빼준다.","imageUrl":null},{"step":2,"text":"베이컨을 한 번 데쳐내 송송 썰어준 후 다진\r\n마늘과 볶아준다.","imageUrl":null},{"step":3,"text":"으깬 감자와 깻잎을 다져서 반죽을 만들고\r\n엄지손가락 크기로 떼어 밀가루를 뿌리고,\r\n둥글게 빚은 후 포크로 자국을 내 뇨끼를 만든다.","imageUrl":null},{"step":4,"text":"만들어진 뇨끼를 삶아 건져준다.","imageUrl":null},{"step":5,"text":"팬에 버터를 넣고 다진양파, 다진마늘, 다진\r\n대파, 볶은 베이컨, 새송이, 흰후추를 볶다가\r\n우유와 생크림, 설탕을 넣고 끓여준다.","imageUrl":null},{"step":6,"text":"뇨끼를 넣어 한 번 더 끓여준 뒤 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00396_2.png', 351.9, 29.1, 13.2, 20.3, 347.2),
  ('397', '호박죽', '일품', '단호박 200g, 찹쌀가루 100g, 브로콜리 50g, 양파 60g, 볶은 현미 25g
버섯마늘소금 2g, 흰후추 1g, 치즈가루 15g', '["단호박","찹쌀가루","브로콜리","양파","볶은 현미","버섯마늘소금","흰후추","치즈가루"]'::jsonb, ARRAY['98d652af-a6d6-440c-9653-e22fc5d47d88','4cb11562-015f-4ab5-969f-0ea8483a0b42','9bf64924-ce53-42bb-849e-7294416e95d6','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','a5bc0b46-0192-496a-b429-d2cb90b2bca9','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','4e0e50d8-ce94-4636-82f5-5bd5ac15d74c']::uuid[], '[{"step":1,"text":"단호박은 껍질을 까고 작게 잘라주고, 양파도\r\n작게 잘라준다.","imageUrl":null},{"step":2,"text":"브로콜리는 뜨거운 물에 데쳐내 준 후 송송\r\n잘라준다.","imageUrl":null},{"step":3,"text":"찹쌀가루는 물 100g에 풀어준다.","imageUrl":null},{"step":4,"text":"단호박과 양파는 물 300g에 삶아준다.","imageUrl":null},{"step":5,"text":"단호박과 양파가 익으면 믹서에 갈아서 다시\r\n끓여준 뒤 찹쌀가루물을 넣어 끓여준다.","imageUrl":null},{"step":6,"text":"호박죽이 끓어오르면 치즈가루를 넣어준 후\r\n볶은 현미랑 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00397_2.png', 150.1, 26.8, 5.6, 2.3, 101.4),
  ('398', '라이스버거떡갈비', '반찬', '라이스버거 : 밥 200g, 맛간장 15g, 전분가루 15g, 팽이버섯 20g, 흰후추 1g, 달걀 60g
떡갈비 : 다진소고기 50g, 다진돼지고기 50g, 다진양파 30g, 다진쪽파 15g, 맛간장 10g, 후추 1g
토마토겉절이 : 토마토 80g, 미나리 20g, 맛간장 5g, 청고추 15g, 홍고추 15g', '["라이스버거 : 밥","맛간장","전분가루","팽이버섯","흰후추","달걀","떡갈비 : 다진소고기","다진돼지고기","다진양파","다진쪽파","후추","토마토겉절이 : 토마토","미나리","청고추","홍고추"]'::jsonb, ARRAY['f175019d-5a93-4cd4-aabc-e7e79445f15a','cafedf96-06e9-46a2-a6e2-6cf6f6b15e70','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','c7d438a6-34d6-423f-905d-446b839e2f39','70e914d4-0d03-4202-8b66-81bd8499aa08','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','dc7b2b73-74de-4fb8-9274-a5967ca444f9','30b5d53c-d247-4f04-9b50-c0f728e65cf9']::uuid[], '[{"step":1,"text":"팽이버섯을 송송 다진 후 라이스버거 재료로\r\n라이스버거를 만들어준다.","imageUrl":null},{"step":2,"text":"만들어준 버거는 팬에 구워준다.","imageUrl":null},{"step":3,"text":"토마토와 미나리를 먹기 좋게 잘라서 겉절이를\r\n만들어준다.","imageUrl":null},{"step":4,"text":"떡갈비 재료로 떡 갈비를 만들어준다.","imageUrl":null},{"step":5,"text":"만들어진 떡갈비를 구워준다.","imageUrl":null},{"step":6,"text":"접시에 토마토 겉절이를 담고 라이스버거와\r\n떡갈비를 올려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00398_2.png', 206.2, 28.3, 12.4, 4.8, 206.1),
  ('399', '고추김치', '반찬', ' 오이고추(40g), 영양부추(5g), 연근(5g), 무(5g)
, 해물육수(8g), 어간장(3g)
, 고춧가루(3g), 생강청(3g), 통깨(1g)', '["오이고추","영양부추","연근","무","해물육수","어간장","고춧가루","생강청","통깨"]'::jsonb, ARRAY['058648c3-fd8e-476d-952f-b15dc67f1877','b20f623d-e722-42af-9bd1-7c11b5e15aa6','f80c9a7d-1510-44e2-a82b-28b9f684e191','f175019d-5a93-4cd4-aabc-e7e79445f15a','84104c49-0af4-4323-a56b-b67002a422d9','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc']::uuid[], '[{"step":1,"text":"오이고추는 배를 갈라 씨를 제거하고 세척 후 절임물에 절여준다.","imageUrl":null},{"step":2,"text":"영양부추, 연근은 송송 다지고 무는 채 썬다.","imageUrl":null},{"step":3,"text":"손질한 부추와 연근, 무에 절임물을 조금 넣고 절인다.","imageUrl":null},{"step":4,"text":"고춧가루, 생강청, 통깨를 절임채소에 섞어 소를 만든다.","imageUrl":null},{"step":5,"text":"오이고추 속에 소를 채워 넣는다.","imageUrl":null},{"step":6,"text":"오이고추를 그릇에 담고 남은 물을 부어 마무리한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/20230306/20230306052031_1678090831734.jpg', 16.1, 2.6, 0.6, 0.3, 16.8),
  ('500', '누룽닭', '반찬', '닭가슴살(120g), 생강즙(5g), 정종(10g), 시금치(20g)
당근(20g), 양파(20g), 샐러리(20g), 파프리카(20g)
느타리(20g), 주꾸미(30g), 새우(20g), 청경채(20g)
누룽지(50g), 튀김기름(200g), 육수(200g), 저염간장(10g)
녹말가루(10g), 마늘(10g), 소금(0.2g), 후춧가루(0.1g)', '["닭가슴살","생강즙","정종","시금치","당근","양파","샐러리","파프리카","느타리","주꾸미","새우","청경채","누룽지","튀김기름","육수","저염간장","녹말가루","마늘","소금","후춧가루"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','9a7f4da6-531b-4478-89ff-d73beafcad1b','e38c12a7-43cb-421a-a36e-7ef0d32517fa','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','12d2d4c9-705a-47f1-b628-30e042a970f8','5e79d288-1400-4817-bd20-e5e6041821b1','c3f77c6a-2dd2-4592-875f-0aa74771d6d0','6f10b4ad-53a2-4a07-ba89-19a6b074373d','7ac59c14-e767-4f32-a2e5-d558c1a29dfb','01e8d2cd-f98c-4ae3-a198-8b001bbf688e','a7a59e81-de3d-4893-b56a-b2218732a25b','a4c37075-c03b-47bb-8aed-5e907620f5d2','f175019d-5a93-4cd4-aabc-e7e79445f15a','6613d1d9-80a2-4ce4-9d3d-647203197e53','fc6e31ce-388e-45cd-956b-b238b9134eb1','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"닭은 포를 떠서 생강즙과 정종을 섞어\r\n발라 놓는다.","imageUrl":null},{"step":2,"text":"시금치는 살짝 데쳐 썰고, 당근, 양파,\r\n샐러리, 파프리카는 약 6Cm 길이로\r\n채를 썰어 절반은 닭고기말이에 사용\r\n하고, 절반은 곁들임채소로 사용한다.","imageUrl":null},{"step":3,"text":"느타리는 끓는 물에 소금을 넣고 데쳐\r\n손으로 찢어놓고, 포를 뜬 닭가슴살에\r\n느타리와 썰어 놓은 채소를 넣어 말아\r\n주고, 육수를 끓여서 말아놓은 닭을\r\n넣고 익혀낸다.","imageUrl":null},{"step":4,"text":"주꾸미와 새우는 끓는 물에 살짝 데치고,\r\n청경채는 반으로 썰어 살짝 데쳐 준비\r\n한다.","imageUrl":null},{"step":5,"text":"튀김기름 온도가 180℃ 정도 되면\r\n누룽지를 넣고 튀겨 기름을 밭쳐 놓는다.","imageUrl":null},{"step":6,"text":"닭을 넣은 육수(③)에 간장과 녹말,\r\n마늘, 소금, 후춧가루를 넣고 끓이다가,\r\n곁들임채소로 남겨 놓은 채소(②)와\r\n데쳐 놓은 해물 및 청경채를 넣고 한 번 더\r\n끓인 뒤 튀겨진 누룽지를 넣어 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00500_2.png', 415.5, 47.5, 23.8, 14.5, 290.9),
  ('501', '광어스테이크', '반찬', '광어(150g), 소금(0.3g), 후춧가루(0.02g), 밀가루(20g)
달걀(50g), 아몬드(20g), 호두(20g), 올리브오일(20g)
, 플레인요거트(50g), 꿀(10g), 레몬즙(20g)', '["광어","소금","후춧가루","밀가루","달걀","아몬드","호두","올리브오일","플레인요거트","꿀","레몬즙"]'::jsonb, ARRAY['2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','aab3b0b9-d346-4697-a1c8-1b1530153788','c7d438a6-34d6-423f-905d-446b839e2f39','52ba316f-8e7f-415f-8079-9a9d674c9adf','7651578f-1206-499d-a04c-15f034d4cae2','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','bb41a88a-ea2b-4830-876d-91fe7f640296','286d1783-cd34-4aae-ac8b-006529ec8bc5','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67']::uuid[], '[{"step":1,"text":"광어는 포를 길게 떠서 소금과\r\n후춧가루에 밑간을 해 놓는다.","imageUrl":null},{"step":2,"text":"아몬드와 호두는 입자있게 다져\r\n준비한다.","imageUrl":null},{"step":3,"text":"밑간이 되어 있는 광어포에 밀가루와\r\n달걀물을 입힌다.","imageUrl":null},{"step":4,"text":"달걀물을 입힌 광어살에 다시 다져\r\n놓은 견과류를 입혀 준다.","imageUrl":null},{"step":5,"text":"팬에 올리브 오일을 넣고, 팬이 따끈해\r\n지면 광어 살을 조심스럽게 앞뒤로\r\n익혀 접시에 담는다.","imageUrl":null},{"step":6,"text":"플레인요거트에 꿀과 레몬즙을 넣고\r\n골고루 섞어 광어스테이크소스를\r\n만들어 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00501_2.png', 487.2, 19.8, 32.2, 31, 192.9),
  ('502', '치즈감자크로켓', '후식', '감자(150g), 생크림(20g), 당근(20g), 양파(20g), 오이(20g)
소금(0.5g), 모짜렐라치즈(50g), 밀가루(20g), 달걀(50g)
빵가루(50g), 튀김기름(400g)', '["감자","생크림","당근","양파","오이","소금","모짜렐라치즈","밀가루","달걀","빵가루","튀김기름"]'::jsonb, ARRAY['20894da1-739d-4d52-b5fe-4943bd3492d5','af187077-b7f6-4b0e-9e99-f844f6359ac2','e38c12a7-43cb-421a-a36e-7ef0d32517fa','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','2cf0c12b-f248-4012-8f53-303c730a7b3d','4e0e50d8-ce94-4636-82f5-5bd5ac15d74c','aab3b0b9-d346-4697-a1c8-1b1530153788','c7d438a6-34d6-423f-905d-446b839e2f39','45080597-55fa-42dc-aa65-12d7694e4b7e','a7a59e81-de3d-4893-b56a-b2218732a25b']::uuid[], '[{"step":1,"text":"감자는 껍질을 벗겨 삶는다.","imageUrl":null},{"step":2,"text":"오이와 당근은 어슷썰기를 하고 양파는\r\n채를 썰어놓는다.","imageUrl":null},{"step":3,"text":"썰어 놓은 채소에 소금과 물을 넣고\r\n살짝 절여, 물기를 짜놓는다.","imageUrl":null},{"step":4,"text":"삶아 놓은 감자를 채에 내리고\r\n생크림을 넣어 섞는다.","imageUrl":null},{"step":5,"text":"생크림을 넣은 감자에 절여 놓은 채소와\r\n모짜렐라치즈를 넣고 골고루 섞는다.","imageUrl":null},{"step":6,"text":"섞여진 감자를 크로켓 모양을 만들어\r\n밀가루, 달걀물, 빵가루를 묻혀 튀김기름\r\n170~180℃ 온도에서 바삭하게 튀겨\r\n냅킨에 올려 기름을 제거하고, 접시에\r\n담아 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00502_2.png', 588.5, 40.1, 14.8, 41, 362.3),
  ('503', '코코넛밀크카레', '반찬', '두부(100g), 소금(0.3g), 코코넛밀크(20g), 당근(20g)
양파(20g), 브로컬리(20g), 돼지고기(50g), 감자(20g)
버터(10g), 카레가루(30g), 물(250g)', '["두부","소금","코코넛밀크","당근","양파","브로컬리","돼지고기","감자","버터","카레가루","물"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','2cf0c12b-f248-4012-8f53-303c730a7b3d','e38c12a7-43cb-421a-a36e-7ef0d32517fa','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','9bf64924-ce53-42bb-849e-7294416e95d6','70e914d4-0d03-4202-8b66-81bd8499aa08','20894da1-739d-4d52-b5fe-4943bd3492d5','7aabd532-361f-4240-aa33-6bfa1be4bc4e','495b9f1e-aa3b-4506-9bb8-feb0a493901e','94786475-832c-4f97-aab7-bf6fbbe2236b']::uuid[], '[{"step":1,"text":"두부는 소창에 넣고, 짜서 물기를\r\n제거하고, 으깨어 놓는다.","imageUrl":null},{"step":2,"text":"으깬 두부에 소금과 코코넛 밀크를\r\n넣고 골고루 섞는다.","imageUrl":null},{"step":3,"text":"섞여진 두부를 김이 오른 찜통에 넣고\r\n약 5분 정도 찐다.","imageUrl":null},{"step":4,"text":"당근과 양파는 사각지게 썰고,\r\n브로컬리는 데쳐 당근 크기로 썰어\r\n놓는다.","imageUrl":null},{"step":5,"text":"돼지고기와 감자는 당근 크기로 썰어\r\n주고, 냄비에 버터를 녹여 돼지고기를\r\n먼저 볶다가 양파와 당근, 감자,\r\n브로컬리를 넣고 다시 볶아 준 뒤,\r\n쪄놓은 두부를 넣어 한 번 더 볶아준다.","imageUrl":null},{"step":6,"text":"볶아지는 냄비(⑤)에 카레 가루를 넣고\r\n살짝 더 볶아준 뒤, 물을 넣고 자작하게\r\n끓여 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00503_2.png', 330.2, 27, 24, 14, 389.6),
  ('504', '소고기리조또롤', '밥', '쌀(50g), 강황가루(20g), 버터(10g)
마늘(10g), 양파(20g), 새송이(30g), 파프리카(30g)
소고기(150g), 소금(0.1g), 후춧가루(0.02g)
하얀된장(10g), 생크림(20g), 육수(200g)', '["쌀","강황가루","버터","마늘","양파","새송이","파프리카","소고기","소금","후춧가루","하얀된장","생크림","육수"]'::jsonb, ARRAY['a5bc0b46-0192-496a-b429-d2cb90b2bca9','a7cf6fb8-b34f-4cfe-a4af-d8e000090dcb','7aabd532-361f-4240-aa33-6bfa1be4bc4e','fc6e31ce-388e-45cd-956b-b238b9134eb1','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','5e79d288-1400-4817-bd20-e5e6041821b1','1c49d1f4-5781-474d-818d-bd7002a4dc0b','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','af187077-b7f6-4b0e-9e99-f844f6359ac2','a4c37075-c03b-47bb-8aed-5e907620f5d2']::uuid[], '[{"step":1,"text":"쌀은 불려 놓고, 마늘은 작게 다지고,\r\n양파는 새송이와 파프리카와 함께\r\n입자를 크게 다져 준비한다.","imageUrl":null},{"step":2,"text":"소고기는 포를 넓게 떠서 소금과\r\n후춧가루를 뿌려 밑간을 해 놓는다.","imageUrl":null},{"step":3,"text":"냄비에 버터를 넣고, 마늘과 양파를\r\n먼저 볶다가, 새송이와 파프리카를\r\n넣는다.","imageUrl":null},{"step":4,"text":"③번에 다시 불린 쌀과 강화를 넣고,\r\n볶다가 불을 줄여, 쌀이 익을 때까지\r\n익혀 준다.","imageUrl":null},{"step":5,"text":"쌀이 익으면, 밑간이 되어 있는\r\n소고기에 넣고 돌돌 말아 준비한다.","imageUrl":null},{"step":6,"text":"하얀 된장에 생크림을 넣어 골고루 섞고,\r\n냄비에 육수를 넣고 생크림을 섞은 하얀\r\n된장을 넣어 끓으면, 말아놓은 소고기를\r\n넣고 은근히 졸여 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00504_2.png', 382.5, 18.7, 36, 18.2, 416.6),
  ('505', '둥지튀김', '반찬', '닭고기살(150g), 소금(0.3g), 후춧가루(0.2g), 달걀(50g)
녹말가루(20g), 백년초국수(20g), 뽕잎국수(20g)
치자국수(20g), 튀김기름(400g)
, 레몬(10g), 설탕(20g), 연유(10g), 물(50g)
다진 마늘(10g), 생강(5g), 식초(20g), 녹말가루(20g)', '["닭고기살","소금","후춧가루","달걀","녹말가루","백년초국수","뽕잎국수","치자국수","튀김기름","레몬","설탕","연유","물","다진 마늘","생강","식초"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','c7d438a6-34d6-423f-905d-446b839e2f39','6613d1d9-80a2-4ce4-9d3d-647203197e53','a7a59e81-de3d-4893-b56a-b2218732a25b','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','06e6f3e7-0293-469d-a338-11a610f3e71b','94786475-832c-4f97-aab7-bf6fbbe2236b','fc6e31ce-388e-45cd-956b-b238b9134eb1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','6c285c60-022a-4a00-b172-87df97f16a2f']::uuid[], '[{"step":1,"text":"닭고기살은 작게 썰어 소금과 후춧\r\n가루를 살짝 뿌려 밑간을 하고 달걀을\r\n넣어 섞는다.","imageUrl":null},{"step":2,"text":"달걀을 넣어 섞은 닭고기 살에 녹말\r\n가루를 넣어 골고루 묻힌다.","imageUrl":null},{"step":3,"text":"국수는 각각 끓는 물에 살짝 데쳐 물기를\r\n빼놓는다.","imageUrl":null},{"step":4,"text":"물기가 빠진 국수는 튀김기름 170℃\r\n온도에서 각각 작은 채에 그대로 살짝\r\n튀겨 둥지를 만든 후 기름을 냅킨에\r\n빼 놓는다.","imageUrl":null},{"step":5,"text":"녹말가루를 묻힌 닭고기살도 튀김\r\n기름에 튀겨 기름을 빼 놓은 둥지국수\r\n위에 올린다.","imageUrl":null},{"step":6,"text":"냄비에 레몬과 설탕을 넣고 물을 넣어\r\n끓이다가 레몬은 건져 내고, 마늘과\r\n생강, 연유, 식초, 녹말을 풀어 넣고\r\n살짝 한 번 더 끓여 녹말소스를 만들어,\r\n튀겨진 닭고기 위에 올려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00505_2.png', 1028.5, 149.1, 242.2, 37.3, 74.9),
  ('506', '새우와스테이크', '일품', '새우(60g), 버터(10g), 소고기(120g), 로즈마리(2g)
소금(0.3g), 후춧가루(2g)
, 와인(50g), 설탕(20g), 당근(20g), 양파(20g)
토마토(30g), 마늘(20g), 대파(10g), 발사믹소스(20g)
, 아스파라거스(20g), 브로컬리(20g)
새송이(20g), 가지(30g)', '["새우","버터","소고기","로즈마리","소금","후춧가루","와인","설탕","당근","양파","토마토","마늘","대파","발사믹소스","아스파라거스","브로컬리","새송이","가지"]'::jsonb, ARRAY['6f10b4ad-53a2-4a07-ba89-19a6b074373d','7aabd532-361f-4240-aa33-6bfa1be4bc4e','1c49d1f4-5781-474d-818d-bd7002a4dc0b','722e0bf6-fae4-4bb8-bb95-f7b407b085d7','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','e16eaf50-ebd3-4933-a774-3ce6fc92593f','06e6f3e7-0293-469d-a338-11a610f3e71b','e38c12a7-43cb-421a-a36e-7ef0d32517fa','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','fc6e31ce-388e-45cd-956b-b238b9134eb1','4b410642-7bf9-45ad-9055-e7d9a34edaa1','5245db59-9275-49a8-b4cd-0426d7262ae4','a8462d27-4ef1-4919-ae9b-10c8f8b9545f','9bf64924-ce53-42bb-849e-7294416e95d6','3e12cf79-2cde-4309-9f7c-4eccce3fde28']::uuid[], '[{"step":1,"text":"새우는 꼬리를 자르고 내장을 제거\r\n한다.","imageUrl":null},{"step":2,"text":"스테이크 소고기는 소금과 로즈마리를\r\n뿌리고 후춧가루를 살짝 뿌려 놓는다.","imageUrl":null},{"step":3,"text":"아스파라거스는 팬에 기름 없이\r\n굽는다.","imageUrl":null},{"step":4,"text":"새송이와 가지는 길게 썰어 브로컬리와\r\n함께 기름 없이 팬에 살짝 구워 놓는다.","imageUrl":null},{"step":5,"text":"팬에 버터를 살짝 넣고 새우를 굽고,\r\n스테이크를 구워 접시에 담는다.","imageUrl":null},{"step":6,"text":"팬에 와인과 설탕을 넣고 끓이다가,\r\n당근, 양파와 토마토 마늘, 대파를 다져\r\n넣고 볶듯이 끓이다가 발사믹소스를\r\n넣고 한 번 더 졸인 소스를 스테이크\r\n위에 얹고, 브로컬리와 새송이, 가지,\r\n아스파라거스를 함께 놓아 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00506_2.png', 508.4, 6.3, 36.2, 37.6, 194.4),
  ('507', '함초삼겹', '반찬', '통삼겹살(150g), 함초가루(10g), 소금(0.5g), 후춧가루(0.2g)
