  ('425', '새콤한연어샐러드', '반찬', '연어 60g, 어린잎 20g, 말린 토마토 15g, 양파 50g, 2가지색 미니파프리카 70g
소스 : 유자청 30g, 감식초 15g, 정종 100ml, 볶은소금 0.5g', '["연어","어린잎","말린 토마토","양파","소스 : 유자청","감식초","정종","볶은소금"]'::jsonb, ARRAY['35db7cf0-556e-49d8-b6d2-f6e1b1e12e16','bc0ebb76-798a-40fe-be99-557ca2b9a9b4','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','2cf0c12b-f248-4012-8f53-303c730a7b3d']::uuid[], '[{"step":1,"text":"연어는 얇게 모양을 살려 슬라이스 한 후\r\n정종에 소금을 섞어 분무기에 넣어 냉장고에\r\n넣어둔다.","imageUrl":null},{"step":2,"text":"건조된 방울토마토는 올리브오일과 후추로\r\n양념하여 사용한다.","imageUrl":null},{"step":3,"text":"양상추는 먹기 좋은 크기로 뜯어 어린잎과\r\n함께 찬물에 담가 물기를 제거한 후 사용한다.","imageUrl":null},{"step":4,"text":"유자청과 감식초는 함께 섞어 믹서에 갈아\r\n드레싱소스를 완성한다.","imageUrl":null},{"step":5,"text":"양파는 모양을 살려 얇게 슬라이스 하여\r\n찬물에 담가 물기를 제거한 뒤 사용한다.","imageUrl":null},{"step":6,"text":"샐러드 접시에 준비된 모든 채소를 담고,\r\n연어는 장미 모양으로 접어서 보기좋게 담아\r\n드레싱 소스를 곁들여 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00425_2.png', 118.3, 5.4, 8.6, 6.9, 48.1),
  ('426', '논우렁순무섞박지', '반찬', '콜라비 200g, 논우렁 100g, 미나리 25g, 양파 60g, 청고추 15g, 홍고추 15g, 대파 10g
양념 : 고춧가루 20g, 생강청 15g, 저염간장 15g, 다진마늘 15g, 플레인요구르트 15g', '["콜라비","논우렁","미나리","양파","청고추","홍고추","대파","양념 : 고춧가루","생강청","저염간장","다진마늘","플레인요구르트"]'::jsonb, ARRAY['715e97fc-4781-4f58-8be6-fbfe30b9abe6','dc7b2b73-74de-4fb8-9274-a5967ca444f9','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','30b5d53c-d247-4f04-9b50-c0f728e65cf9','4b410642-7bf9-45ad-9055-e7d9a34edaa1','c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','f175019d-5a93-4cd4-aabc-e7e79445f15a','fc6e31ce-388e-45cd-956b-b238b9134eb1','bb41a88a-ea2b-4830-876d-91fe7f640296']::uuid[], '[{"step":1,"text":"콜라비는 껍질을 벗긴 후 저염간장에 30분\r\n정도 절여준다.","imageUrl":null},{"step":2,"text":"우렁은 뜨거운 물에 데친 후 행군 뒤 물기를\r\n빼준다.","imageUrl":null},{"step":3,"text":"미나리는 먹기 좋은 크기로 잘라준다.","imageUrl":null},{"step":4,"text":"다진대파, 청홍고추, 양파는 송송 잘라준다.","imageUrl":null},{"step":5,"text":"양념장에 콜라비부터 버무린 뒤 모든 재료를\r\n섞어서 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00426_2.png', 103, 18.6, 6.5, 0.3, 616.5),
  ('427', '코다리맑은탕', '국&찌개', '코다리 200g, 무 60g, 감자 60g, 양파 15g, 청양고추 30g
미나리 25g, 백일송이버섯 25g, 참기름 15g
국물 : 다진마늘 15g, 저염간장 15g, 흰후추 1g', '["코다리","무","감자","양파","청양고추","미나리","백일송이버섯","참기름","국물 : 다진마늘","저염간장","흰후추"]'::jsonb, ARRAY['f80c9a7d-1510-44e2-a82b-28b9f684e191','20894da1-739d-4d52-b5fe-4943bd3492d5','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','30b5d53c-d247-4f04-9b50-c0f728e65cf9','dc7b2b73-74de-4fb8-9274-a5967ca444f9','0c0ade94-cfd8-4104-b44c-40e942cac482','f175019d-5a93-4cd4-aabc-e7e79445f15a','bcb746cd-29c8-4bb2-93e4-5832b8adfa94']::uuid[], '[{"step":1,"text":"코다리는 먹기 좋게 잘라서 물에 헹궈 물기를\r\n빼준다.","imageUrl":null},{"step":2,"text":"감자와 무, 백일송이버섯, 미나리는 먹기 좋게\r\n썰어준다.","imageUrl":null},{"step":3,"text":"양파, 청양고추도 먹기 좋게 썰어준다.","imageUrl":null},{"step":4,"text":"냄비에 참기름을 넣어 코다리를 살짝 볶아준다.","imageUrl":null},{"step":5,"text":"코다리를 볶은 냄비에 무, 감자, 국물 재료를\r\n넣고 충분히 끓인다.","imageUrl":null},{"step":6,"text":"끓고 있는 국에 양파, 청양고추, 백일송이\r\n버섯을 올려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00427_2.png', 162.3, 7.7, 24.2, 3.9, 110.8),
  ('530', '세가지샐러드', '반찬', '연두부(100g), 닭고기살(50g), 통후추(1g), 단호박(20g)
바나나(20g), 파프리카(20g), 토마토(20g), 어린잎(10g)
, 마(20g), 생크림(20g), 요거트(20g), 식초(5g)
올리브오일(10g), 설탕(10g), 흑임자(5g), 잣(10g)', '["연두부","닭고기살","통후추","단호박","바나나","파프리카","토마토","어린잎","마","생크림","요거트","식초","올리브오일","설탕","흑임자","잣"]'::jsonb, ARRAY['4566cac5-9166-4c0d-906a-bfc7360f8f5b','e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','98d652af-a6d6-440c-9653-e22fc5d47d88','1a4b39f8-b581-46dc-bd7e-289cd6160711','5e79d288-1400-4817-bd20-e5e6041821b1','aa597bcd-596b-4cbe-a2c4-3da0d060cb50','bc0ebb76-798a-40fe-be99-557ca2b9a9b4','a988ffbb-92c3-4c68-8cea-a2f10c329015','af187077-b7f6-4b0e-9e99-f844f6359ac2','bb41a88a-ea2b-4830-876d-91fe7f640296','6c285c60-022a-4a00-b172-87df97f16a2f','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','06e6f3e7-0293-469d-a338-11a610f3e71b','9e00a5b9-84e6-4cdc-afb9-0ee2bd3342fc','bbbbd533-8922-4dac-9e4c-cd93ea710c92']::uuid[], '[{"step":1,"text":"연두부는 동글게 썰어 준비한다.","imageUrl":null},{"step":2,"text":"호박은 갈라 씨를 제거 하고 껍질을\r\n벗겨 쪄서 작은 깍둑썰기로 썰어 준비\r\n한다.","imageUrl":null},{"step":3,"text":"바나나와 파프리카 토마토는 호박과\r\n같은 크기의 작은 깍두기로 썰어 놓는다.","imageUrl":null},{"step":4,"text":"닭고기살은 통후추를 넣고 약 20분 정도\r\n삶아 건져 작은 깍두기로 썰어 준비한다.","imageUrl":null},{"step":5,"text":"마와 잣, 흑임자를 갈아 놓은 뒤 생크림,\r\n요거트, 식초, 올리브오일, 설탕을\r\n섞어 샐러드 소스를 만들어 놓는다.","imageUrl":null},{"step":6,"text":"썰어 놓은 연두부 위에 호박 , 닭고기,\r\n토마토, 파프리카를 각각 올린 뒤 어린\r\n잎을 올리고 소스를 뿌려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00530_2.png', 202.4, 12.6, 16.1, 9.8, 209.2),
  ('531', '애호박들깨볶음', '반찬', '애호박(150g), 소금(0.5g), 양파(20g), 대파(10g)
홍고추(10g), 들기름(20g), 다진 마늘(5g), 건새우(20g)
들깨가루(30g)', '["애호박","소금","양파","대파","홍고추","들기름","다진 마늘","건새우","들깨가루"]'::jsonb, ARRAY['88c94a13-dc8a-4e66-ab19-08fc2ea82c77','2cf0c12b-f248-4012-8f53-303c730a7b3d','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','4b410642-7bf9-45ad-9055-e7d9a34edaa1','30b5d53c-d247-4f04-9b50-c0f728e65cf9','f5534afd-2a26-4493-8ec1-fd680dcb3bef','fc6e31ce-388e-45cd-956b-b238b9134eb1','6f10b4ad-53a2-4a07-ba89-19a6b074373d','184687ba-0cba-4fec-bb21-33fe300c2073']::uuid[], '[{"step":1,"text":"애호박은 반달 모양으로 썰어 준다.","imageUrl":null},{"step":2,"text":"썰어 놓은 호박에 소금을 넣고 살짝\r\n절여 물기를 제거하고 준비한다.","imageUrl":null},{"step":3,"text":"양파는 채를 썰고, 대파는 1/4로 자르고,\r\n홍고추는 어슷썰어 자연스럽게 씨를\r\n제거해 놓는다.","imageUrl":null},{"step":4,"text":"팬에 들기름을 넣고, 마늘을 먼저\r\n볶는다.","imageUrl":null},{"step":5,"text":"볶아진 팬에 건새우를 넣어 볶아준다.","imageUrl":null},{"step":6,"text":"건새우가 볶아지면, 썰어 놓은 호박을\r\n넣어 볶다가 양파와 대파를 넣어\r\n볶으면서 들깨 가루와 넣어 살짝\r\n볶으면서 마지막에 썰어 놓은 홍고추를\r\n넣어 한 번만 더 볶아 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00531_2.png', 184.6, 16.2, 10.4, 8.7, 202),
  ('532', '고구마바나나샐러드', '반찬', '고구마(100g), 바나나(100g), 요거트(30g), 어린잎(20g)
잣(5g), 연유(20g)', '["고구마","바나나","요거트","어린잎","잣","연유"]'::jsonb, ARRAY['4b4f0113-01cf-4dc6-ae1f-30f09e99746b','1a4b39f8-b581-46dc-bd7e-289cd6160711','bb41a88a-ea2b-4830-876d-91fe7f640296','bc0ebb76-798a-40fe-be99-557ca2b9a9b4','bbbbd533-8922-4dac-9e4c-cd93ea710c92']::uuid[], '[{"step":1,"text":"고구마는 찜통에 약 20분 정도 쪄서\r\n껍질을 벗겨 준비한다.","imageUrl":null},{"step":2,"text":"뜨거운 고구마가 한김 빠지면, 곱게\r\n으깨 놓는다.","imageUrl":null},{"step":3,"text":"으깨진 고구마에 바나나를 썰어\r\n요거트와 함께 넣는다.","imageUrl":null},{"step":4,"text":"3번에 다시 연유를 넣어 골고루 섞는다.","imageUrl":null},{"step":5,"text":"잣은 종이를 깔고 곱게 다져 준비한다.","imageUrl":null},{"step":6,"text":"어린잎은 물에 담그어, 건져 물기를\r\n제거해 놓고, 으깬 고구마에 다진 잣을\r\n넣어 샐러드를 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00532_2.png', 348.8, 64.8, 4.8, 7.8, 111.4),
  ('533', '누룽지새우튀김', '반찬', '새우(100g), 소금(0.3g), 후춧가루(0.02g)
튀김가루(100g), 달걀(50g), 누룽지(50g), 튀김기름(200g)
, 오렌지주스(100g), 설탕(10g), 식초(10g)
, 어린잎(20g)', '["새우","소금","후춧가루","튀김가루","달걀","누룽지","튀김기름","오렌지주스","설탕","식초","어린잎"]'::jsonb, ARRAY['6f10b4ad-53a2-4a07-ba89-19a6b074373d','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','aab3b0b9-d346-4697-a1c8-1b1530153788','c7d438a6-34d6-423f-905d-446b839e2f39','01e8d2cd-f98c-4ae3-a198-8b001bbf688e','a7a59e81-de3d-4893-b56a-b2218732a25b','19eb37dc-2b1c-4e89-a931-31a38ae60561','06e6f3e7-0293-469d-a338-11a610f3e71b','6c285c60-022a-4a00-b172-87df97f16a2f','bc0ebb76-798a-40fe-be99-557ca2b9a9b4']::uuid[], '[{"step":1,"text":"새우는 껍질을 제거하고 소금과\r\n후춧가루를 넣어 밑간을 해놓는다.","imageUrl":null},{"step":2,"text":"어린잎은 찬물에 담그어 놓는다.","imageUrl":null},{"step":3,"text":"튀김가루에 달걀을 넣어 잘 섞어\r\n튀김반죽을 만들어 놓는다.","imageUrl":null},{"step":4,"text":"밑간을 해 놓은 새우를 튀김반죽에\r\n넣어 옷을 입힌다.","imageUrl":null},{"step":5,"text":"누룽지는 170℃의 온도 튀김 기름에\r\n튀겨내고, 튀김옷 입힌 새우도 튀겨낸다.","imageUrl":null},{"step":6,"text":"냄비에 오렌지주스와 설탕, 식초를\r\n넣어 은근히 졸여 소스를 만들고,\r\n어린잎은 찬물에 건져 물기를 제거하고\r\n접시에 깔고 튀긴 누룽지와 튀긴 새우를\r\n올려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00533_2.png', 558, 63.5, 23.5, 23.3, 156.7),
  ('534', '백김치주꾸미샐러드', '반찬', '백김치(100g), 주꾸미(100g), 파(10g), 양상추(10g)
홍고추(10g), 어린잎(10g)
, 저염간장(20g), 식초(10g), 설탕(10g)
꿀(10g), 레몬(10g), 양파(20g), 마늘(10g)', '["백김치","주꾸미","파","양상추","홍고추","어린잎","저염간장","식초","설탕","꿀","레몬","양파","마늘"]'::jsonb, ARRAY['133f214e-50f4-431d-af36-d97f6c9d4f9b','c3f77c6a-2dd2-4592-875f-0aa74771d6d0','4b410642-7bf9-45ad-9055-e7d9a34edaa1','1389717e-81e4-4350-96d4-d627d851aa10','30b5d53c-d247-4f04-9b50-c0f728e65cf9','bc0ebb76-798a-40fe-be99-557ca2b9a9b4','f175019d-5a93-4cd4-aabc-e7e79445f15a','6c285c60-022a-4a00-b172-87df97f16a2f','06e6f3e7-0293-469d-a338-11a610f3e71b','286d1783-cd34-4aae-ac8b-006529ec8bc5','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','fc6e31ce-388e-45cd-956b-b238b9134eb1']::uuid[], '[{"step":1,"text":"백김치는 살짝 씻어 물기를 제거하고\r\n잘게 썰어 준비한다.","imageUrl":null},{"step":2,"text":"양파와 마늘은 다지고 파는 채를 썰어\r\n놓는다.","imageUrl":null},{"step":3,"text":"어린잎은 찬 물에 담그어 놓았다가,\r\n다시 소창에 건져 물기를 빼 놓는다.","imageUrl":null},{"step":4,"text":"냄비에 물을 넣고, 양파와 파를 넣어\r\n끓이다가 준비한 쭈구미를 넣고\r\n부드럽게 데쳐 썰어 놓는다.","imageUrl":null},{"step":5,"text":"식초와 간장, 설탕, 꿀, 레몬, 다진양파,\r\n다진마늘을 넣고 잘 섞어서 샐러드\r\n드레싱을 만든다.","imageUrl":null},{"step":6,"text":"준비한 백김치(①)와 주꾸미(②)를\r\n섞은 후 양상추를 접시에 깔고, 그 위에\r\n섞어놓은 백김치와 주꾸미를 올리고,\r\n홍고추와 어린잎을 위에 장식으로 올린\r\n후 샐러드 소스를 뿌려 완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00534_2.png', 125.5, 3.9, 22.2, 2.3, 656.6),
  ('535', '닭고기월남쌈', '반찬', '닭고기살(100g), 로즈마리(5g), 양파(20g), 소금(0.5g)
후춧가루(0.02g), 오이(30g), 파프리카(30g), 당근(30g)
라이스페이퍼(20g), 녹말가루(30g), 식용유(20g)
, 다진 마늘(10g), 고춧가루(10g), 설탕(20g)
식초(20g), 레몬즙(10g)', '["닭고기살","로즈마리","양파","소금","후춧가루","오이","파프리카","당근","라이스페이퍼","녹말가루","식용유","다진 마늘","고춧가루","설탕","식초","레몬즙"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','722e0bf6-fae4-4bb8-bb95-f7b407b085d7','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','5e79d288-1400-4817-bd20-e5e6041821b1','e38c12a7-43cb-421a-a36e-7ef0d32517fa','241e49d7-4aa4-4411-8ded-350a16b41222','6613d1d9-80a2-4ce4-9d3d-647203197e53','a7a59e81-de3d-4893-b56a-b2218732a25b','fc6e31ce-388e-45cd-956b-b238b9134eb1','84104c49-0af4-4323-a56b-b67002a422d9','06e6f3e7-0293-469d-a338-11a610f3e71b','6c285c60-022a-4a00-b172-87df97f16a2f','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67']::uuid[], '[{"step":1,"text":"닭고기살에 로즈마리를 뿌려 약 3시간\r\n이상 숙성을 시킨다.","imageUrl":null},{"step":2,"text":"냄비에 물을 1/3쯤 넣고, 양파채를 썰어\r\n넣어 끓으면, 숙성된 닭고기살을 넣고\r\n약 20분 정도 삶아 건진다.","imageUrl":null},{"step":3,"text":"삶아 건진 닭고기살을 한 김 빼고, 길게\r\n손으로 찢어 소금과 후춧가루에 살짝\r\n무치고, 오이와 파프리카는 씨를 제거\r\n하고 채를 썰고, 당근도 오이채의 길이에\r\n맞게 채를 썰어 준비해 놓는다.","imageUrl":null},{"step":4,"text":"마늘을 다지고, 고춧가루와 설탕, 식초,\r\n레몬즙을 넣어 소스를 만든다.","imageUrl":null},{"step":5,"text":"뜨거운 물에 라이스페이퍼를 살짝 넣어\r\n바로 건진다.","imageUrl":null},{"step":6,"text":"건져 놓은 라이스페이퍼에 준비한\r\n닭고기살과 파프리카, 오이, 당근 넣고\r\n돌돌 말아, 녹말가루를 살짝 입혀, 팬에\r\n굴리듯 익혀 완성하고, 준비해 놓은\r\n소스와 함께 제공한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00535_2.png', 353.7, 40.1, 28.5, 8.8, 197),
  ('536', '양배추롤', '반찬', '닭고기살(100g), 천일염(0.5g), 후춧가루(0.3g), 식용유(10g)
정종(10g), 양배추(80g), 부추(30g), 깻잎(10g)
홍파프리카(20g), 노랑파프리카(20g), 당근(20g), 양파(20g)
, 요거트(20g), 머스터드(20g), 꿀(10g), 레몬즙(10g)
설탕(5g)', '["닭고기살","천일염","후춧가루","식용유","정종","양배추","부추","깻잎","홍파프리카","노랑파프리카","당근","양파","요거트","머스터드","꿀","레몬즙","설탕"]'::jsonb, ARRAY['e4027a6b-8af8-4ed1-9a86-082e9b2f4e05','2cf0c12b-f248-4012-8f53-303c730a7b3d','bcb746cd-29c8-4bb2-93e4-5832b8adfa94','a7a59e81-de3d-4893-b56a-b2218732a25b','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','fd4254d4-2691-47e1-9367-c2b820ef8d00','058648c3-fd8e-476d-952f-b15dc67f1877','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','5e79d288-1400-4817-bd20-e5e6041821b1','e38c12a7-43cb-421a-a36e-7ef0d32517fa','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','bb41a88a-ea2b-4830-876d-91fe7f640296','5b59cfae-1277-48af-99a6-833687e2da0b','286d1783-cd34-4aae-ac8b-006529ec8bc5','6205dc23-e07f-4ddf-bfd8-4f17dfe4db67','06e6f3e7-0293-469d-a338-11a610f3e71b']::uuid[], '[{"step":1,"text":"닭고기살은 천일염과 후춧가루를 뿌려\r\n마리네이드를 해놓는다.","imageUrl":null},{"step":2,"text":"양배추와 부추는 김이 오른 찜통에\r\n쪄서 식혀 놓는다.","imageUrl":null},{"step":3,"text":"깻잎은 채를 썰고, 파프리카는 속을 제거\r\n하고 5cm 길이로 채를 썰고, 당근과\r\n양파도 같은 길이로 채를 썰어 놓는다.","imageUrl":null},{"step":4,"text":"마리네이드를 해 놓은 닭고기살은 팬에\r\n기름을 두르고, 팬이 따끈해지면 앞뒤를\r\n돌려가며 정종을 살살 뿌려 닭고기살을\r\n굽고, 닭고기살이 익으면 살을 찢어 준비\r\n한다.","imageUrl":null},{"step":5,"text":"요거트와 머스터드, 꿀 ,레몬즙, 설탕을\r\n넣고 고루 섞어 소스를 만들어 놓는다.","imageUrl":null},{"step":6,"text":"쪄 놓은 양배추에 준비한 채소(③)와\r\n닭고기살(④)을 넣고, 돌돌 말아 쪄\r\n놓은 부추로 양배추를 묶어 완성하고,\r\n만들어 놓은 요거트 소스를 함께 제공\r\n한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00536_2.png', 164.8, 14.8, 17.5, 3.9, 111.5),
  ('537', '단호박소고기롤', '반찬', '소고기(70g), 저염간장(10g), 다진 마늘(10g), 설탕(10g)
파프리카(30g), 오이(20g), 적양배추(20g), 사과(20g)
설탕(10g), 팽이버섯(20g), 무순(5g)
, 단호박(100g), 밀가루(50g), 소금(0.5g)
, 다진 마늘(10g), 다진 양파(20g), 올리브오일(20g)
설탕(10g), 식초(20g), 소금(0.5g)', '["소고기","저염간장","다진 마늘","설탕","파프리카","오이","적양배추","사과","팽이버섯","무순","단호박","밀가루","소금","다진 양파","올리브오일","식초"]'::jsonb, ARRAY['1c49d1f4-5781-474d-818d-bd7002a4dc0b','f175019d-5a93-4cd4-aabc-e7e79445f15a','fc6e31ce-388e-45cd-956b-b238b9134eb1','06e6f3e7-0293-469d-a338-11a610f3e71b','5e79d288-1400-4817-bd20-e5e6041821b1','9dca47c9-8d7a-47b3-b5a7-3c9825cd6e6a','fd4254d4-2691-47e1-9367-c2b820ef8d00','c85a52b9-c3b4-4a76-951c-bb40edeb3adb','cafedf96-06e9-46a2-a6e2-6cf6f6b15e70','f09d1d41-602a-441c-a7bc-520311490ceb','98d652af-a6d6-440c-9653-e22fc5d47d88','aab3b0b9-d346-4697-a1c8-1b1530153788','2cf0c12b-f248-4012-8f53-303c730a7b3d','61a6a6cd-c3d6-4ba2-a033-f6e0b38bc742','a8ac1f24-c286-4f4c-b9fc-d9b88b5d75dc','6c285c60-022a-4a00-b172-87df97f16a2f']::uuid[], '[{"step":1,"text":"단호박은 1/8 등분으로 갈라 속을\r\n파내고 찜통에서 약 15~20분 정도\r\n충분히 쪄낸다.","imageUrl":null},{"step":2,"text":"소고기는 채를 썰어 마늘, 간장, 설탕에\r\n양념을 하고 팬에 볶아서 식힌다.","imageUrl":null},{"step":3,"text":"파프리카와 오이, 적양배추는 채를\r\n썰고, 무순은 물에 잠시 담그어 놓고,\r\n사과는 채를 썰어 설탕물에 잠시 담그어\r\n놓고, 팽이버섯은 밑둥만 잘라 한 줌\r\n집기 좋은 크기로 준비해 놓는다.","imageUrl":null},{"step":4,"text":"다진마늘과 다진 양파 ,올리브오일,\r\n설탕, 식초, 소금을 넣고, 골고루 섞어\r\n소스를 만들어 놓는다.","imageUrl":null},{"step":5,"text":"쪄 낸 단호박은 껍질을 벗기고 채에\r\n곱게 내려 밀가루와 물, 소금을 조금\r\n섞어 단호박 반죽을 만들어 놓는다.","imageUrl":null},{"step":6,"text":"팬에 올리브 오일을 바르고, 만들어\r\n놓은 단호박 반죽을 한 국자씩 떠 넣어,\r\n밀전병을 만들고, 밀전병이 익으면,\r\n한 김 식혀, 그 안에 소고기 볶음과\r\n채소를 넣어 돌돌 말아 소스와 함께\r\n완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00537_2.png', 444.9, 66.9, 10.2, 15.2, 248.3),
  ('538', '생선카레튀김', '반찬', '생선살(150g), 생강(10g), 정종(10g), 녹말가루(10g)
깻잎(10g)
, 콩가루(20g), 밀가루(10g), 카레가루(10g)
녹말가루(10g), 달걀(50g)
, 마요네즈(20g), 요구르트(20g), 설탕(10g), 식초(10g)
, 양상추(30g)', '["생선살","생강","정종","녹말가루","깻잎","콩가루","밀가루","카레가루","달걀","마요네즈","요구르트","설탕","식초","양상추"]'::jsonb, ARRAY['c8e908a8-e613-4f21-a98e-89bb5e2d4bf9','1a3a0bb7-9681-4d47-86ca-c141bcbc92d1','6613d1d9-80a2-4ce4-9d3d-647203197e53','3c38eb1c-6ef4-4bb8-82be-74f679ce9e91','c1a987ee-fe94-4eb5-b3e7-d41c23cd3445','aab3b0b9-d346-4697-a1c8-1b1530153788','495b9f1e-aa3b-4506-9bb8-feb0a493901e','c7d438a6-34d6-423f-905d-446b839e2f39','549c7365-28e9-491f-9040-412558f93a5c','bb41a88a-ea2b-4830-876d-91fe7f640296','06e6f3e7-0293-469d-a338-11a610f3e71b','6c285c60-022a-4a00-b172-87df97f16a2f','1389717e-81e4-4350-96d4-d627d851aa10']::uuid[], '[{"step":1,"text":"생선살에 생강즙과 정종을 넣고 약 30분\r\n정도 숙성을 시켜 비릿한 맛 제거 및 생선\r\n살의 탱탱함을 살려준다.","imageUrl":null},{"step":2,"text":"콩가루와 밀가루, 카레가루, 녹말가루,\r\n달걀을 넣고 골고루 섞어 튀김 반죽을\r\n만들어 놓는다.","imageUrl":null},{"step":3,"text":"깻잎은 반으로 접어 채를 썰어 물에\r\n잠시 담그어 놓는다.","imageUrl":null},{"step":4,"text":"깻잎(③)은 물기를 제거하고\r\n튀김반죽(②)을 골고루 입힌다.","imageUrl":null},{"step":5,"text":"숙성시킨 생선살(①)에 녹말가루를\r\n살짝 입히고 튀김 반죽(②)을 골고루\r\n입힌 뒤, 튀김반죽을 입힌 깻잎(④)을\r\n얹어 튀김 기름 170℃ 온도에 넣어\r\n약 2분 정도 튀겨 기름을 자연스럽게\r\n빼 놓는다.","imageUrl":null},{"step":6,"text":"마요네즈와 요구르트, 설탕, 식초를\r\n넣어 골고루 섞어 튀김소스를 만들고,\r\n튀김을 접시에 담아 양상추와 함께 얹어\r\n완성한다.","imageUrl":null}]'::jsonb, 'http://www.foodsafetykorea.go.kr/uploadimg/cook/10_00538_2.png', 555, 14, 22.4, 45.5, 260.2),
  ('539', '삼겹가지볶음', '반찬', '삼겹살(100g), 생강(5g), 정종(10g), 가지(50g), 양파(20g)
